const QUESTIONS_CHFI_C3 = [
  { id:70501, domain:4, level:1, question:"Which Windows registry hive stores per-user configuration settings for the currently logged-on user?", options:["HKEY_CURRENT_USER, which maps to that user's NTUSER.DAT loaded at logon time","HKEY_LOCAL_MACHINE, which holds global hardware and software settings for the machine","HKEY_CLASSES_ROOT, which primarily maps file extensions to their handler programs","HKEY_USERS default subtree, which only stores the template profile for new accounts"], correct:0, explanation:"HKCU maps to the logged-on user's NTUSER.DAT. HKLM is machine-wide, not per-user, so it is wrong here." },
  { id:70502, domain:4, level:2, question:"On disk, where does the Windows registry hive HKLM\\SYSTEM physically reside for forensic acquisition?", options:["Inside the NTUSER.DAT file located in each individual user's profile directory","In %SystemRoot%\\System32\\config\\SYSTEM as a binary hive file on the volume","In the pagefile.sys at the root of the system volume alongside virtual memory","In the Recycle Bin metadata files stored under the $Recycle.Bin container folder"], correct:1, explanation:"The SYSTEM hive lives in System32\\config. NTUSER.DAT holds HKCU data, not the SYSTEM hive, so that option is wrong." },
  { id:70503, domain:4, level:2, question:"Which registry key records the most recently used programs and helps establish user program execution?", options:["The Run key under the Software hive, which only lists auto-start programs at boot time as commonly encountered in real casework","The MountedDevices key, which merely maps drive letters to physical volume identifiers","The UserAssist key under NTUSER.DAT, which logs GUI program launches with ROT13 encoding","The TypedURLs key, which stores addresses typed into the Internet Explorer address bar"], correct:2, explanation:"UserAssist logs GUI-launched programs (ROT13 encoded). The Run key lists autostart entries, not usage history, so it is wrong." },
  { id:70504, domain:4, level:3, question:"An examiner needs to prove a USB device was connected. Which registry location is MOST authoritative?", options:["The TypedPaths key, which only records folder paths typed into Windows Explorer's bar","The RecentDocs key, which tracks recently opened documents but not device connections","The Prefetch directory, which stores execution traces for applications rather than devices","The USBSTOR key under SYSTEM\\CurrentControlSet\\Enum, listing connected USB storage devices"], correct:3, explanation:"USBSTOR under Enum enumerates connected USB storage. RecentDocs tracks documents, not device attachment, so it is wrong." },
  { id:70505, domain:4, level:1, question:"What is the primary forensic value of Windows Prefetch (.pf) files?", options:["They show that a program was executed, including run counts and last-run timestamps","They contain the full source code of the executed application for reverse engineering","They store user passwords in plaintext used to authenticate the running application","They record every network packet sent and received by the application during runtime"], correct:0, explanation:"Prefetch proves execution with run counts and timestamps. It does not store source code or passwords, so those options are wrong." },
  { id:70506, domain:4, level:2, question:"Where are Windows Prefetch files stored by default on a modern Windows system?", options:["In each user's AppData\\Local\\Temp folder, deleted automatically at every logoff event","In C:\\Windows\\Prefetch as .pf files named after the executable plus a path hash","In the System Volume Information folder alongside restore points and shadow copies","In the registry under HKLM\\SOFTWARE as binary values keyed by executable name"], correct:1, explanation:"Prefetch lives in C:\\Windows\\Prefetch as hashed .pf files. It is a directory, not a registry value, so that option is wrong." },
  { id:70507, domain:4, level:3, question:"AmCache.hve and ShimCache differ in what key forensic respect regarding evidence of execution?", options:["ShimCache stores full file hashes while AmCache only stores the file's last access time","Both are identical copies of Prefetch data and provide no additional evidentiary value","AmCache records SHA-1 hashes and paths; ShimCache records paths and can indicate presence not always execution","AmCache is a plaintext log file while ShimCache is encrypted and cannot be parsed offline as commonly encountered in real casework"], correct:2, explanation:"AmCache stores SHA-1 and paths; ShimCache indicates presence and possible execution. ShimCache does not store full hashes, so option one is wrong." },
  { id:70508, domain:4, level:2, question:"Windows Jump Lists are MOST useful to an investigator for determining what?", options:["The BIOS boot order and firmware settings applied during the last system startup","The encryption keys used by BitLocker to protect the contents of the system volume","The list of installed device drivers and their corresponding version numbers on disk as commonly encountered in real casework","Recently and frequently accessed files and folders associated with specific applications"], correct:3, explanation:"Jump Lists track recent/frequent files per application. They contain no BIOS or BitLocker key data, so those options are wrong." },
  { id:70509, domain:4, level:2, question:"A Windows shortcut (.LNK) file is valuable because it typically preserves what information?", options:["The target file path, volume serial number, and original and modified MAC timestamps","Only a thumbnail image of the target file with no path or timestamp information at all","The complete contents of the target file embedded for offline recovery when deleted","A cryptographic signature proving the user who created the shortcut and their password"], correct:0, explanation:"LNK files preserve target path, volume serial, and timestamps. They do not embed full file contents, so that option is wrong." },
  { id:70510, domain:4, level:1, question:"Which Windows Event Log records successful and failed logon events by default?", options:["The Application log, which primarily captures errors emitted by installed software programs","The Security log, which records audit events including logon success and failure entries","The Setup log, which only documents operating system installation and update operations","The Forwarded Events log, which merely aggregates events collected from remote machines"], correct:1, explanation:"Logon auditing is written to the Security log. The Application log captures software errors, not logons, so it is wrong." },
  { id:70511, domain:4, level:2, question:"Which Windows Security Event ID indicates a successful account logon on modern Windows?", options:["Event ID 1102, which specifically records that the security audit log itself was cleared","Event ID 7045, which records that a new service was installed on the target system","Event ID 4624, which records a successful logon along with logon type and account name","Event ID 4688, which records that a new process was created by an account on the host"], correct:2, explanation:"4624 is successful logon. 4688 is process creation and 1102 is log clearing, so those are wrong for a logon." },
  { id:70512, domain:4, level:2, question:"When a file is sent to the Recycle Bin on modern Windows, what do the $I and $R files represent?", options:["$I holds the recovered file body while $R stores only a checksum used to verify it","$I and $R are both encrypted containers that require the user's password to open them as commonly encountered in real casework","Both files are identical backups written for redundancy in case one becomes corrupted","$I stores original path and deletion time metadata while $R holds the actual file contents"], correct:3, explanation:"$I holds metadata (path, deletion time) and $R holds the content. They are not identical backups, so that option is wrong." },
  { id:70513, domain:4, level:3, question:"SRUM (System Resource Usage Monitor) is forensically valuable primarily because it records what?", options:["Per-application network data usage, energy use, and process activity over roughly 30-60 days","The plaintext contents of all files opened by each application during the monitored period as commonly encountered in real casework","A byte-for-byte copy of RAM captured every hour and stored in an encrypted database","The full browsing history of every installed web browser merged into a single timeline"], correct:0, explanation:"SRUM logs per-app resource and network usage over time. It does not copy RAM or file contents, so those options are wrong." },
  { id:70514, domain:4, level:2, question:"The Windows hibernation file (hiberfil.sys) is useful to a memory forensics examiner because it contains what?", options:["Only the master boot record and partition table copied for disaster recovery use","A compressed snapshot of system RAM written to disk when the machine hibernated","The BitLocker recovery key in plaintext for decrypting the protected system volume","A rolling log of every keystroke entered by the user during the current session"], correct:1, explanation:"hiberfil.sys holds a compressed RAM snapshot. It is not an MBR copy or a keystroke log, so those options are wrong." },
  { id:70515, domain:4, level:2, question:"Windows ShellBags are MOST useful for establishing what during an investigation?", options:["The exact CPU clock speed and thermal readings recorded during folder browsing sessions","The list of antivirus signatures downloaded and applied during scheduled update windows","Evidence that a user browsed to and viewed specific folders, including now-deleted ones","The sequence of BIOS POST codes generated at each system power-on since installation"], correct:2, explanation:"ShellBags show folder browsing/view state, including deleted folders. They record no CPU or BIOS data, so those are wrong." },
  { id:70516, domain:4, level:1, question:"Where does Windows store scheduled task definitions that a forensic examiner should review?", options:["Exclusively inside the pagefile.sys, which is wiped on every clean system shutdown as commonly encountered in real casework","Only within volatile RAM, meaning tasks are lost the moment the machine powers off","In C:\\Windows\\System32\\Tasks as XML files and in the Schedule registry keys","Inside the Recycle Bin, because scheduled tasks are treated as recoverable deleted items"], correct:3, explanation:"Tasks are stored as XML under System32\\Tasks plus registry keys. They persist across reboots, so the RAM-only option is wrong." },
  { id:70517, domain:4, level:2, question:"On a Linux system, which file most reliably records the history of commands typed in a user's bash shell?", options:["The ~/.bash_history file in the user's home directory, subject to session flush timing","The /etc/passwd file, which only defines account names, UIDs, and login shell paths as commonly encountered in real casework","The /proc/cpuinfo file, which merely describes the processor features of the host","The /boot/grub/grub.cfg file, which only stores the bootloader menu configuration"], correct:0, explanation:"~/.bash_history stores shell command history. /etc/passwd defines accounts, not commands, so it is wrong." },
  { id:70518, domain:4, level:2, question:"Which Linux directory provides a virtual filesystem exposing live kernel and process state?", options:["The /var/log directory, which persists rotated text logs written by system daemons","The /proc pseudo-filesystem, which exposes per-process and kernel data in memory","The /home directory, which simply contains the personal files of each local user account","The /etc directory, which stores static system-wide configuration files on the disk"], correct:1, explanation:"/proc is the virtual filesystem for live process/kernel state. /var/log holds persistent logs, not live state, so it is wrong." },
  { id:70519, domain:4, level:2, question:"On a systemd-based Linux host, which command reads the binary journal that replaced many text logs?", options:["The cat /var/log/syslog command, which only works on hosts still using rsyslog output","The tail -f /etc/fstab command, which merely displays mount definitions, not logs","The journalctl command, which queries the systemd journal binary log database","The dmesg -c command, which clears and prints only the kernel ring buffer messages"], correct:2, explanation:"journalctl reads the systemd journal. dmesg only shows the kernel ring buffer, not the full journal, so it is wrong." },
  { id:70520, domain:4, level:1, question:"Which Linux file defines scheduled cron jobs that run on behalf of the system as a whole?", options:["The /root/.ssh/authorized_keys file, which lists public keys allowed to log in as root","The /var/spool/mail directory, which merely stores incoming mail messages per user","The ~/.profile script, which only runs interactively when a login shell first starts","The /etc/crontab file plus /etc/cron.d, which define system-wide scheduled jobs"], correct:3, explanation:"/etc/crontab and /etc/cron.d hold system cron jobs. authorized_keys is for SSH auth, not scheduling, so it is wrong." },
  { id:70521, domain:4, level:2, question:"On macOS, configuration and application data are commonly stored in what file format?", options:["Property list (plist) files, stored in either XML or binary form under Library folders","Windows registry hives copied over during migration from a prior Windows machine","Plain .ini files identical to legacy Windows configuration files in every respect as commonly encountered in real casework","ELF binaries that must be disassembled before any configuration value can be read"], correct:0, explanation:"macOS uses plist files (XML or binary). It does not use Windows registry hives, so that option is wrong." },
  { id:70522, domain:4, level:2, question:"macOS FSEvents logs are forensically useful because they record what type of activity?", options:["The plaintext of every email sent and received through the built-in Mail application","A history of filesystem changes such as file and directory creation and deletion","The exact GPS coordinates of the Mac at the moment each application was launched","A complete copy of the Safari browsing cache retained for offline reconstruction"], correct:1, explanation:"FSEvents records filesystem change history. It does not capture email bodies or GPS, so those options are wrong." },
  { id:70523, domain:4, level:3, question:"Which macOS subsystem consolidates system and application log messages into a queryable store?", options:["The legacy /var/log/messages file alone, which Apple still writes all events to today","The Time Machine backup index, which only tracks which files were backed up and when","The Unified Logging system, accessed via the log command and stored in .tracev3 files","The Spotlight metadata store, which only indexes file contents for fast local searching"], correct:2, explanation:"Unified Logging (.tracev3, log command) consolidates logs. Spotlight indexes content, it is not the log store, so it is wrong." },
  { id:70524, domain:4, level:2, question:"macOS Spotlight metadata (the .Spotlight-V100 store) can help an investigator establish what?", options:["The firmware version of the T2 security chip installed on the logic board of the Mac","The exact wattage drawn by the display backlight during each indexed search operation as commonly encountered in real casework","The list of Wi-Fi access points the Mac connected to during the indexing time window","File metadata such as names, kinds, and timestamps, useful for building a file timeline"], correct:3, explanation:"Spotlight metadata yields file names, kinds, and timestamps for timelines. It does not store firmware versions, so that is wrong." },
  { id:70525, domain:4, level:1, question:"Which open-source framework is the industry standard for analyzing memory (RAM) images?", options:["The Volatility Framework, which parses memory images to extract processes and artifacts","The Wireshark suite, which is designed to capture and dissect live network packets","The Autopsy platform, which is chiefly a graphical front end for disk image analysis as commonly encountered in real casework","The Nmap scanner, which enumerates open ports and services on remote network hosts"], correct:0, explanation:"Volatility is the standard RAM analysis framework. Wireshark analyzes packets, not memory images, so it is wrong." },
  { id:70526, domain:4, level:2, question:"In Volatility, which plugin family lists the running processes found in a memory image?", options:["The connscan plugin, which scans for TCP connection structures rather than processes","The pslist and psscan plugins, which enumerate active and hidden processes respectively","The hivelist plugin, which only locates the offsets of registry hives loaded in memory as commonly encountered in real casework","The dlldump plugin, which extracts loaded DLL modules to disk for later examination"], correct:1, explanation:"pslist/psscan enumerate processes. connscan finds network connections, not processes, so it is wrong." },
  { id:70527, domain:4, level:2, question:"When acquiring RAM from a live system, why should the examiner minimize their footprint?", options:["Because reading RAM permanently corrupts the disk's partition table and boot sector","Because RAM acquisition automatically reboots the machine and clears all volatile data as commonly encountered in real casework","Because acquisition tools consume memory and can overwrite volatile evidence still present","Because Windows blocks all memory reads unless the analyst first disables the firewall"], correct:2, explanation:"Acquisition tools use memory and may overwrite volatile evidence, so footprint matters. RAM reads do not corrupt the partition table, so that is wrong." },
  { id:70528, domain:4, level:3, question:"An examiner suspects process hollowing. Which memory artifact best reveals injected or hidden code?", options:["The pagefile modification timestamp alone, which only shows when swapping last occurred","The BIOS event log, which records hardware faults but nothing about process memory regions as commonly encountered in real casework","The prefetch run count, which indicates execution frequency but not in-memory injection","Discrepancies between on-disk image and in-memory process pages, found via malfind and comparisons"], correct:3, explanation:"malfind and disk-vs-memory comparison expose injected pages. Prefetch run counts show frequency, not injection, so that is wrong." },
  { id:70529, domain:4, level:2, question:"Which Volatility plugin reveals network connections present at the time a memory image was captured?", options:["The netscan plugin, which recovers TCP and UDP endpoints and their owning process IDs","The filescan plugin, which only enumerates FILE_OBJECT structures for open files","The cmdline plugin, which merely prints the command-line arguments of each process","The svcscan plugin, which enumerates Windows services registered on the imaged host as commonly encountered in real casework"], correct:0, explanation:"netscan recovers network endpoints and owning PIDs. filescan lists file objects, not connections, so it is wrong." },
  { id:70530, domain:4, level:2, question:"Where does Google Chrome store its browsing history on a Windows system?", options:["In a plaintext file named history.txt saved directly on the user's Windows desktop","In an SQLite database named History under the user's Chrome User Data profile folder","In the Windows registry under a dedicated ChromeHistory key inside the HKCU hive","In the pagefile.sys, from which entries must be carved because Chrome keeps no file as commonly encountered in real casework"], correct:1, explanation:"Chrome stores history in an SQLite 'History' database in the profile. It is not a registry key, so that option is wrong." },
  { id:70531, domain:4, level:2, question:"Firefox stores browsing history and bookmarks primarily in which database file?", options:["A binary file called index.dat identical to the legacy Internet Explorer history format","The cookies.txt file, which actually holds only session cookies and no history at all","A Windows registry hive that Firefox loads at startup and unloads when the browser closes","places.sqlite, an SQLite database inside the user's Firefox profile directory"], correct:3, explanation:"Firefox uses places.sqlite for history/bookmarks. index.dat is an old IE format, not Firefox, so that option is wrong." },
  { id:70532, domain:4, level:1, question:"Microsoft Edge (Chromium-based) stores its artifacts in a structure most similar to which browser?", options:["Google Chrome, because both are built on Chromium and use SQLite databases in profiles","Netscape Navigator 4, sharing that browser's proprietary and long-obsolete cache format","Lynx, the text-only browser, which stores no persistent history or cache whatsoever","Internet Explorer 6, relying entirely on the legacy index.dat binary storage files"], correct:0, explanation:"Chromium Edge mirrors Chrome's SQLite profile layout. It does not use IE6's index.dat, so that option is wrong." },
  { id:70533, domain:4, level:2, question:"When reconstructing web activity, why is the browser cache valuable in addition to history?", options:["The cache stores the user's saved passwords in plaintext for every visited website","The cache retains copies of downloaded page resources such as images and HTML pages","The cache is the only place that records the URLs typed into the address bar directly","The cache holds the private encryption keys used for every HTTPS session the user made"], correct:1, explanation:"Cache retains actual page resources (images, HTML). It does not store plaintext passwords or TLS keys, so those are wrong." },
  { id:70534, domain:4, level:3, question:"An investigator finds a Chrome download record. Which artifact confirms the file actually reached disk?", options:["The presence of the URL in the browser's autocomplete suggestions from earlier typing as commonly encountered in real casework","The favicon cache entry for the originating website stored alongside the history data","The downloads table showing state complete, corroborated by the file's presence on disk and its timestamps","The mere existence of a bookmark pointing at the download page the user had visited"], correct:2, explanation:"A completed downloads-table entry plus the file on disk confirms delivery. A bookmark alone does not prove download, so that is wrong." },
  { id:70535, domain:4, level:2, question:"In email forensics, which part of a message is MOST useful for tracing its true origin?", options:["The email signature block, which the sender can freely edit to display any information as commonly encountered in real casework","The subject line, which summarizes content but carries no routing information at all","The display name, which mail clients render but which is trivially spoofed by senders","The full internet headers, especially the Received lines that record each relaying server"], correct:3, explanation:"Received headers trace relaying servers and origin. The display name is easily spoofed and not authoritative, so it is wrong." },
  { id:70536, domain:4, level:1, question:"Which file format is used by Microsoft Outlook to store an offline cached copy of a mailbox?", options:["The OST file, an offline folder store that syncs with the Exchange server mailbox","The MBOX file, which is the native storage format used by Outlook on every version","The DBX file, which is actually the legacy Outlook Express message store format","The EML file, which stores exactly one message rather than an entire mailbox"], correct:0, explanation:"OST is Outlook's offline store. MBOX is a Unix mail format, not Outlook's native store, so that option is wrong." },
  { id:70537, domain:4, level:2, question:"A single email exported as an individual file is most commonly saved in which format?", options:["The PST format, which is designed to hold an entire mailbox rather than one message","The EML format, an RFC 822 text file containing one message with headers and body","The OST format, which is an offline synchronization store tied to an Exchange account","The MBOX format, which concatenates many messages into one large mailbox container"], correct:1, explanation:"EML holds a single RFC 822 message. PST and MBOX are multi-message containers, so they are wrong for a single message." },
  { id:70538, domain:4, level:2, question:"Which protocol, seen in email headers and logs, is used to SEND mail between servers?", options:["POP3, which is a retrieval protocol that downloads messages to a client from a server","IMAP, which synchronizes and manages mail folders on the server for client access","SMTP, the Simple Mail Transfer Protocol used to submit and relay outbound messages","HTTP, which serves web pages and is not used for server-to-server mail transport"], correct:2, explanation:"SMTP sends/relays mail. POP3 and IMAP are retrieval protocols, not sending, so they are wrong." },
  { id:70539, domain:4, level:2, question:"MBOX and Maildir are two ways Unix mail systems store messages. How do they differ?", options:["MBOX encrypts every message while Maildir stores all messages entirely in plaintext as commonly encountered in real casework","MBOX is a Windows-only format while Maildir can only exist on macOS installations","Both are byte-identical formats and the names are simply interchangeable synonyms","MBOX concatenates messages in one file while Maildir stores each message as a separate file"], correct:3, explanation:"MBOX is one file of concatenated messages; Maildir uses one file per message. They are not identical, so that option is wrong." },
  { id:70540, domain:4, level:1, question:"What is the primary goal of password cracking during a forensic examination?", options:["To recover access to encrypted or protected evidence such as archives or user accounts","To permanently delete the suspect's password so the account can never be used again","To transmit the recovered password to the suspect as required by chain-of-custody rules","To increase the entropy of the password so the evidence becomes harder to analyze"], correct:0, explanation:"The goal is to recover access to protected evidence. Deleting the password would destroy access, so that option is wrong." },
  { id:70541, domain:4, level:2, question:"Which password-cracking approach tries every possible combination and is guaranteed to succeed eventually?", options:["A dictionary attack, which is limited to words present in the chosen wordlist file","A brute-force attack, which exhaustively tries all combinations given enough time","A rainbow-table lookup, which fails outright whenever the hashes are properly salted","A social-engineering attempt, which relies on tricking a person rather than computation"], correct:1, explanation:"Brute force tries all combinations and eventually succeeds. A dictionary attack only tests wordlist entries, so it is not guaranteed." },
  { id:70542, domain:4, level:2, question:"Why are salted password hashes resistant to precomputed rainbow-table attacks?", options:["Salting encrypts the hash with the user's private key so no table can ever match it","Salting compresses the hash to a fixed length that rainbow tables cannot represent","Salting deletes the original password so there is no value left for a table to match as commonly encountered in real casework","A unique salt per password means precomputed tables for unsalted hashes no longer apply"], correct:3, explanation:"Per-password salts defeat precomputed tables built for unsalted hashes. Salting does not encrypt with a private key, so that is wrong." },
  { id:70543, domain:4, level:2, question:"Where are Windows local account password hashes stored that an examiner may target for cracking?", options:["In the plaintext file passwords.txt kept in the root of the Windows system directory","In the pagefile.sys exclusively, requiring carving because Windows keeps no hive for them","In the SAM registry hive, with the SYSTEM hive holding the boot key needed to decrypt it","In the Recycle Bin metadata, because expired credentials are moved there automatically"], correct:2, explanation:"Local hashes live in the SAM hive, decrypted with the SYSTEM boot key. There is no passwords.txt file, so that option is wrong." },
  { id:70544, domain:4, level:2, question:"Which registry-related artifact helps show programs configured to launch automatically at startup?", options:["The RecentDocs key, which only lists documents the user recently opened by extension","The TypedURLs key, which records addresses manually entered into the browser address bar","The Run and RunOnce keys under Software, which list programs set to auto-start at logon","The MountedDevices key, which merely maps drive letters to volume unique identifiers"], correct:2, explanation:"Run/RunOnce keys define autostart programs. RecentDocs tracks documents, not autostart, so it is wrong." },
  { id:70545, domain:4, level:3, question:"An examiner needs to correlate a deleted file's original name and deletion time on Windows 10. Which artifact is best?", options:["The pagefile.sys alone, which may contain fragments but rarely the original file name","The BIOS clock reading, which shows current time but nothing about the deleted file","The $I file in $Recycle.Bin, which stores the original path, size, and deletion timestamp","The Prefetch file for explorer.exe, which shows execution but not per-file deletion data as commonly encountered in real casework"], correct:2, explanation:"The $I file stores the original path, size, and deletion time. The Prefetch file shows execution, not per-file deletion data, so it is wrong." },
  { id:70546, domain:4, level:1, question:"What does the acronym MAC refer to in file system timestamp forensics?", options:["Modified, Accessed, and Created (or Changed) timestamps associated with a file entry","Media Access Control, the hardware address burned into a network interface card","Message Authentication Code, a cryptographic checksum verifying message integrity","Mandatory Access Control, a security model enforcing labels on subjects and objects as commonly encountered in real casework"], correct:0, explanation:"In timestamp forensics, MAC means Modified/Accessed/Created. The network MAC address is a different concept, so it is wrong here." },
  { id:70547, domain:4, level:2, question:"On NTFS, which structure records detailed timestamps and is a rich source for timeline analysis?", options:["The FAT allocation table, which NTFS volumes do not use for file metadata at all","The $MFT (Master File Table), whose $STANDARD_INFORMATION and $FILE_NAME attributes hold timestamps","The BIOS parameter block alone, which only describes the volume geometry, not files as commonly encountered in real casework","The pagefile.sys header, which stores swap metadata rather than per-file timestamps"], correct:1, explanation:"The $MFT holds per-file timestamp attributes. The FAT table is not used by NTFS for this, so that option is wrong." },
  { id:70548, domain:4, level:2, question:"Why do investigators compare $STANDARD_INFORMATION and $FILE_NAME timestamps in the MFT?", options:["Because only $FILE_NAME timestamps are ever visible to the user through Windows Explorer","Because the two attributes are stored on different physical disks for redundancy purposes","Because $STANDARD_INFORMATION timestamps cannot be altered by any tool under any condition as commonly encountered in real casework","Because timestomping tools often alter $STANDARD_INFORMATION but not $FILE_NAME, revealing tampering"], correct:3, explanation:"Discrepancies expose timestomping since $FILE_NAME is harder to alter. $STANDARD_INFORMATION can be altered, so option three is wrong." },
  { id:70549, domain:4, level:2, question:"Which artifact records applications that were run, surviving even after the executable is deleted?", options:["ShimCache (AppCompatCache), which retains file paths and can indicate prior program presence","The live process list only, which is lost the moment the machine is powered down","The desktop wallpaper history, which records only cosmetic personalization changes","The printer spooler queue, which stores only pending and recently printed documents as commonly encountered in real casework"], correct:0, explanation:"ShimCache retains paths indicating prior presence/execution. The live process list vanishes at shutdown, so it is wrong." },
  { id:70550, domain:4, level:2, question:"In Linux, which log file traditionally records authentication events such as sudo and SSH logins?", options:["The /etc/hostname file, which merely stores the machine's configured network hostname","The /var/log/auth.log (or secure) file, which records authentication and authorization events","The /proc/meminfo file, which only reports current memory usage statistics of the kernel as commonly encountered in real casework","The /dev/null device, which discards anything written to it and stores nothing at all"], correct:1, explanation:"auth.log/secure records authentication events. /etc/hostname only holds the hostname, so it is wrong." },
  { id:70551, domain:4, level:3, question:"An attacker cleared /var/log files on a Linux host. Where else might login evidence survive?", options:["Only in the deleted /etc/passwd entries, which do not record any login session history","In the systemd journal binary store and in wtmp/utmp, which may retain session records","Exclusively in the BIOS, which does not track operating-system user login activity at all","In the swap partition only, which never contains any authentication-related information as commonly encountered in real casework"], correct:2, explanation:"The systemd journal and wtmp/utmp can retain login data. /etc/passwd holds accounts, not sessions, so that is wrong." },
  { id:70552, domain:4, level:2, question:"Which Linux command displays the last logins recorded in the wtmp file?", options:["The chmod command, which changes file permission bits and reports no login information","The passwd command, which changes account passwords and does not read login records","The mount command, which lists mounted filesystems and has nothing to do with logins","The last command, which parses /var/log/wtmp to display recent user login sessions"], correct:3, explanation:"'last' reads wtmp for login sessions. 'chmod' changes permissions, unrelated to logins, so it is wrong." },
  { id:70553, domain:4, level:1, question:"What kind of evidence does the macOS ~/Library/Preferences directory typically hold?", options:["Application preference plist files reflecting per-user configuration and recent settings","The complete kernel source code compiled into the currently running macOS version as commonly encountered in real casework","Raw disk sectors imaged from external drives that were connected to the Mac","Network packet captures automatically recorded by the operating system firewall"], correct:0, explanation:"Preferences holds per-user plist settings. It does not contain kernel source or packet captures, so those options are wrong." },
  { id:70554, domain:4, level:2, question:"In Volatility, which plugin extracts the command line used to launch each process?", options:["The hashdump plugin, which extracts password hashes rather than any command lines","The cmdline plugin, which displays the full command-line arguments per running process","The mftparser plugin, which parses NTFS MFT records carved from the memory image","The vadinfo plugin, which enumerates virtual address descriptors, not command lines as commonly encountered in real casework"], correct:1, explanation:"cmdline shows process command lines. hashdump extracts credential hashes, not command lines, so it is wrong." },
  { id:70555, domain:4, level:2, question:"Why is the pagefile.sys relevant when disk-only artifacts are insufficient?", options:["Because it stores a signed manifest of every installed application and its version as commonly encountered in real casework","Because it is a read-only mirror of the registry that Windows updates every hour","Because paged-out memory may contain fragments of process data, strings, and prior activity","Because it holds the only authoritative copy of the file system journal for NTFS"], correct:2, explanation:"The pagefile can hold paged-out memory fragments. It is not a registry mirror, so that option is wrong." },
  { id:70556, domain:4, level:3, question:"An examiner wants to prove which document was most recently opened by a user. Which combination is strongest?", options:["Only the file's on-disk creation time, which reflects copy time and not user opening","Only the antivirus scan log, which shows scanning activity but not user document access","The BIOS boot log combined with the printer queue, neither of which tracks document opens as commonly encountered in real casework","RecentDocs and the application's MRU list, corroborated by the LNK file's access timestamp"], correct:3, explanation:"RecentDocs, app MRU, and LNK timestamps together prove recent opening. Creation time reflects copy, not opening, so it is wrong." },
  { id:70557, domain:4, level:2, question:"Which browser artifact stores small pieces of data websites use to track sessions and preferences?", options:["Cookies, stored per profile and readable to reconstruct site logins and tracking activity","The favicon database, which only holds the small site icons shown beside page titles","The prefetch files, which are a Windows execution artifact unrelated to browser sessions as commonly encountered in real casework","The DNS resolver cache, which merely maps hostnames to IP addresses temporarily"], correct:0, explanation:"Cookies store session/preference data per site. Favicons are just site icons, not session data, so that option is wrong." },
  { id:70558, domain:4, level:2, question:"When examining Chrome, the 'Login Data' SQLite file is significant because it stores what?", options:["The complete browsing history including every URL and its precise last-visit timestamp","Saved website usernames and encrypted passwords the browser offered to remember","The list of installed extensions along with their granted permission scopes and IDs","The full cache of downloaded images and page resources for offline viewing later"], correct:1, explanation:"Login Data holds saved usernames and encrypted passwords. History lives in the History DB, not here, so that option is wrong." },
  { id:70559, domain:4, level:2, question:"What does an email 'Message-ID' header provide to an investigator?", options:["The plaintext body of the message, which is actually carried after the header block as commonly encountered in real casework","The sender's physical mailing address, which email headers do not contain at all","A globally unique identifier for the message, useful for correlating copies across systems","The recipient's account password, which is never transmitted within an email header"], correct:2, explanation:"Message-ID uniquely identifies a message for correlation. It is not the body or a password, so those options are wrong." },
  { id:70560, domain:4, level:3, question:"An email appears forged. Which analysis most reliably detects a spoofed sending domain?", options:["Trusting the From display name, which any sender can set to impersonate anyone at will as commonly encountered in real casework","Comparing only the message subject against the body for any inconsistent wording used","Reading only the HTML signature image, which conveys no authentication information","Checking SPF, DKIM, and DMARC results in the Authentication-Results and Received headers"], correct:3, explanation:"SPF/DKIM/DMARC in the headers reveal spoofing. The From display name is trivially forged, so trusting it is wrong." },
  { id:70561, domain:4, level:1, question:"What is the forensic significance of the Windows LNK file's embedded volume serial number?", options:["It can tie a shortcut to the specific volume where the target file originally resided","It reveals the user's login password stored inside the shortcut for quick access as commonly encountered in real casework","It contains the full text of the target document for recovery when it is deleted","It stores the CPU serial number of the machine that created the shortcut file"], correct:0, explanation:"The volume serial ties the LNK to a specific volume. It does not store passwords or document text, so those are wrong." },
  { id:70562, domain:4, level:2, question:"Which artifact in Windows helps determine folders that were accessed on removable media?", options:["The DNS cache, which stores hostname resolutions and nothing about folder browsing","ShellBags, which record folder view and browsing state including paths on removable media","The event log's setup channel, which only records OS installation and servicing events as commonly encountered in real casework","The hosts file, which statically maps hostnames to IPs and records no folder access"], correct:1, explanation:"ShellBags record browsed folders including removable media. The DNS cache stores name resolutions, not folders, so it is wrong." },
  { id:70563, domain:4, level:2, question:"In Linux forensics, what does examining the /etc/cron.d and user crontab files help reveal?", options:["The exact model of the physical hard drive installed inside the examined Linux host as commonly encountered in real casework","The kernel version currently loaded, which is instead reported by the uname command","Scheduled or persistence tasks an attacker may have added to run commands automatically","The contents of the user's private SSH key, which cron files never contain at all"], correct:2, explanation:"Cron files can reveal attacker persistence tasks. They do not store SSH private keys, so that option is wrong." },
  { id:70564, domain:4, level:3, question:"An examiner analyzing a memory image wants to detect a rootkit hiding a process. What approach helps?", options:["Reading only the on-disk prefetch files, which cannot reveal a process hidden in memory","Trusting the running Task Manager output alone, which a rootkit can actively manipulate","Checking only the desktop shortcuts, which have no relationship to hidden process activity","Cross-referencing pslist against psscan to find processes unlinked from the active list"], correct:3, explanation:"psscan can find processes unlinked from pslist, exposing hiding. Task Manager can be manipulated by the rootkit, so trusting it is wrong." },
  { id:70565, domain:4, level:2, question:"Why is the Windows SRUM database (SRUDB.dat) sometimes more useful than firewall logs?", options:["It attributes network data consumption to specific applications over an extended time window","It stores the plaintext of every web page the user viewed during the monitored period as commonly encountered in real casework","It is the only artifact that records the user's typed passwords for network resources","It contains a byte-for-byte copy of the network adapter's firmware for verification"], correct:0, explanation:"SRUM attributes network usage per application over time. It does not store page contents or passwords, so those are wrong." },
  { id:70566, domain:4, level:2, question:"Which artifact indicates the times a specific executable ran, along with a run count, on Windows?", options:["The hosts file, which maps hostnames to IP addresses and records no execution data","The Prefetch (.pf) file for that executable, which stores last-run times and a run count","The desktop.ini file, which only customizes the appearance of the folder it resides in as commonly encountered in real casework","The thumbs.db file, which caches thumbnail images and records nothing about execution"], correct:1, explanation:"The Prefetch file records run times and count. The hosts file maps names to IPs, unrelated to execution, so it is wrong." },
  { id:70567, domain:4, level:2, question:"What is the primary role of the SYSTEM hive's CurrentControlSet in device forensics?", options:["It stores the user's browser bookmarks synced from their signed-in online account","It stores the actual contents of deleted files pending permanent removal from disk","It holds active hardware, driver, and device enumeration data including connected USB devices","It contains the plaintext local account passwords used to authenticate at the logon screen as commonly encountered in real casework"], correct:2, explanation:"CurrentControlSet holds device/driver enumeration such as USB. It does not store bookmarks or file contents, so those are wrong." },
  { id:70568, domain:4, level:3, question:"During malware analysis, which combination best confirms a suspicious process made outbound connections?", options:["Only the file's icon and description resource, which malware can freely forge to look benign","Only the file's compile timestamp, which can be altered and reveals nothing about the network","Only the presence of the file on disk, which alone proves neither execution nor networking","Volatility netscan showing the PID's connections, plus Prefetch or SRUM confirming execution"], correct:3, explanation:"netscan tying a PID to connections plus execution artifacts confirms it. The icon can be forged, so relying on it is wrong." },
  { id:70569, domain:4, level:1, question:"Which macOS artifact records a timeline of file system changes on the volume?", options:["FSEvents logs, stored in the hidden .fseventsd directory at the root of the volume","The BIOS non-volatile RAM, which Macs use for boot settings rather than file events","The Windows Prefetch folder, which does not exist on a native macOS installation","The Linux /proc filesystem, which is not present on standard macOS systems either"], correct:0, explanation:"FSEvents in .fseventsd logs file system changes. Prefetch and /proc do not exist on macOS, so those options are wrong." },
  { id:70570, domain:4, level:2, question:"In email header analysis, why should Received lines be read from bottom to top?", options:["Because the topmost Received line is always inserted by the original sending user's device","Because mail servers prepend each Received line, so the bottom is earliest and the top latest","Because only the bottom line is ever authentic and every line above it is always forged","Because reading order has no forensic meaning and the lines can be interpreted in any order as commonly encountered in real casework"], correct:1, explanation:"Servers prepend Received lines, so bottom is earliest. Reading order does matter, so calling it meaningless is wrong." },
  { id:70571, domain:4, level:2, question:"What information does a PST file contain that makes it central to Outlook email forensics?", options:["Only the user's calendar color preferences with no actual message content stored inside as commonly encountered in real casework","Nothing but a pointer to the Exchange server where all real data must be fetched live","A complete personal store of messages, folders, contacts, and calendar items for the account","Only encrypted network traffic captures unrelated to the mailbox content itself at all"], correct:2, explanation:"A PST is a complete personal store of messages, folders, contacts, and calendar items. It is not a mere pointer to Exchange, so that option is wrong." },
  { id:70572, domain:4, level:3, question:"An examiner must recover deleted emails from a PST file. Which technique is most appropriate?", options:["Only reading the live folder view in Outlook, which by definition omits deleted items as commonly encountered in real casework","Reformatting the drive to force Windows to rebuild the mailbox from backup fragments","Editing the registry TypedURLs key, which has no relationship to PST message recovery","Parsing PST internal structures and free space with forensic tools to carve deleted message blocks"], correct:3, explanation:"Parsing PST internals/free space can recover deleted items. The live folder view omits them, so relying on it is wrong." },
  { id:70573, domain:4, level:2, question:"Which artifact best shows that a user viewed images in a specific folder before those images were deleted?", options:["Thumbcache (thumbnail cache) databases, which retain cached thumbnails of previously viewed images","The DNS cache, which stores hostname resolutions and holds no image thumbnail data at all as commonly encountered in real casework","The hosts file, which statically maps hostnames to IP addresses and no image previews","The pagefile header, which describes swap layout and does not cache viewed images"], correct:0, explanation:"Thumbcache retains thumbnails of viewed images even after deletion. The DNS cache holds name resolutions, not thumbnails, so it is wrong." },
  { id:70574, domain:4, level:2, question:"In Linux, what does the /var/log/syslog (or messages) file primarily contain?", options:["Only the encrypted user passwords, which are actually stored in the shadow file instead","General system and service log messages emitted by the kernel and many daemons","A complete copy of every user's bash command history across all accounts on the host","The raw disk image of the boot partition captured at each system startup event"], correct:1, explanation:"syslog holds general system/service messages. Passwords live in /etc/shadow, not syslog, so that option is wrong." },
  { id:70575, domain:4, level:2, question:"Why might an examiner parse the Windows Amcache.hve during an intrusion investigation?", options:["Because it stores the plaintext domain administrator password used during the compromise as commonly encountered in real casework","Because it is the only file that records inbound firewall connection attempts by port","It records executed or present programs with SHA-1 hashes, aiding identification of malware","Because it holds a full packet capture of the attacker's command-and-control traffic"], correct:2, explanation:"Amcache records program hashes/paths useful for malware ID. It does not store passwords or packet captures, so those are wrong." },
  { id:70576, domain:4, level:3, question:"An examiner suspects log tampering on Windows. Which event most directly indicates the Security log was cleared?", options:["Event ID 4624, which records a successful logon and says nothing about clearing logs","Event ID 4688, which records new process creation, not any log-clearing activity","Event ID 7045, which records a new service installation rather than clearing of logs","Event ID 1102, which specifically records that the Security audit log was cleared"], correct:3, explanation:"1102 records Security log clearing. 4624 is a logon event, unrelated to clearing, so it is wrong." },
  { id:70577, domain:4, level:1, question:"What is the purpose of the Volatility 'imageinfo' or 'kdbgscan' plugin?", options:["To suggest the correct OS profile and identify the memory image's operating system version","To crack the login password of every user account found within the memory image","To reformat the memory image into a bootable disk image for live re-execution","To transmit the memory image to a remote server for cloud-based automated analysis as commonly encountered in real casework"], correct:0, explanation:"imageinfo/kdbgscan identify the OS profile of the image. They do not crack passwords, so that option is wrong." },
  { id:70578, domain:4, level:2, question:"Which artifact would best help attribute file access to a specific user account on a shared Windows PC?", options:["The machine's BIOS serial number, which identifies hardware but not any particular user as commonly encountered in real casework","Per-user NTUSER.DAT artifacts like RecentDocs and UserAssist tied to that account's profile","The single global pagefile.sys, which is shared and not partitioned by user account","The printer's internal page counter, which totals prints but not per-user file access"], correct:1, explanation:"Per-user NTUSER.DAT artifacts attribute activity to an account. The BIOS serial identifies hardware, not a user, so it is wrong." },
  { id:70579, domain:4, level:2, question:"What does the presence of a program in the ShimCache but not in Prefetch typically suggest?", options:["That the program's source code was compiled directly on the machine under examination","That the program encrypted all of its output before writing anything to the local disk","The program may have been present or executed while Prefetch was disabled or the .pf was removed","That the program is guaranteed to be legitimate signed Microsoft operating system software as commonly encountered in real casework"], correct:2, explanation:"ShimCache-only presence suggests execution/presence without a surviving .pf. It does not prove the file is legitimate, so that is wrong." },
  { id:70580, domain:4, level:3, question:"An investigator must build a super-timeline of an incident. Which approach is MOST comprehensive?", options:["Relying solely on the file system creation timestamps visible in Windows Explorer","Using only the browser history from one browser while ignoring every other artifact as commonly encountered in real casework","Reading just the current Task Manager process list and recording those PIDs by hand","Combining MFT, event logs, registry, prefetch, and browser artifacts into one normalized timeline"], correct:3, explanation:"A super-timeline fuses many artifact sources. Explorer creation times alone are far too narrow, so that option is wrong." },
  { id:70581, domain:4, level:1, question:"What does the 'downloads' history in a browser allow an investigator to determine?", options:["Files a user downloaded, including source URLs, target paths, and download timestamps","The user's saved passwords for each site, which are kept in a separate credential store","The complete registry hive of the operating system exported by the browser at exit","The physical memory contents of the browser process at the moment of each download"], correct:0, explanation:"Download history shows files, URLs, paths, and times. Saved passwords are in a separate store, so that option is wrong." },
  { id:70582, domain:4, level:2, question:"Which Linux artifact can reveal recently accessed files through a desktop environment?", options:["The /etc/fstab file, which only defines how filesystems are mounted at boot time","The recently-used.xbel file in the user's config, which logs recently opened documents","The /proc/version file, which only reports the running kernel build string of the host","The /dev/random device, which produces entropy and stores no file access records at all"], correct:1, explanation:"recently-used.xbel logs recently opened documents. /etc/fstab defines mounts, not file access, so it is wrong." },
  { id:70583, domain:4, level:2, question:"What is the role of the DKIM signature found in an email header?", options:["It encrypts the entire message body so that only the intended recipient can ever read it","It stores the sender's mailbox password to authenticate them to the receiving mail server as commonly encountered in real casework","It cryptographically signs selected headers and body, letting receivers verify domain and integrity","It records the GPS location from which the sender composed and dispatched the message"], correct:2, explanation:"DKIM signs headers/body so receivers verify domain and integrity. It does not encrypt the body, so that option is wrong." },
  { id:70584, domain:4, level:3, question:"An examiner needs to confirm a USB device's first and last connection times on Windows. What is best?", options:["Only the file explorer window title, which shows the current path but no connection history","Only the Recycle Bin timestamps, which relate to deletions rather than device attachment","Only the desktop wallpaper change date, which is cosmetic and unrelated to any device","Correlating USBSTOR/USB registry keys with the setupapi.dev.log and Event Log device events"], correct:3, explanation:"USBSTOR keys plus setupapi.dev.log and event logs give connection times. Recycle Bin times relate to deletions, so that is wrong." },
  { id:70585, domain:4, level:1, question:"What does the Volatility 'dlllist' plugin provide about a given process?", options:["The list of dynamic-link libraries (DLLs) loaded into that process's address space","The password hash of the user account that originally started the target process as commonly encountered in real casework","A complete disk image of every file the process ever opened during its lifetime","The BIOS firmware version of the machine from which the memory was captured"], correct:0, explanation:"dlllist shows DLLs loaded by a process. It does not extract password hashes, so that option is wrong." },
  { id:70586, domain:4, level:2, question:"Which artifact in Windows records the last write time useful for pinpointing when a key changed?", options:["Every registry value stores its own last-write time individually for each named value","Each registry KEY has a LastWrite timestamp, which reflects when the key was last modified","The registry stores no timestamps at all, so key change times must be inferred elsewhere as commonly encountered in real casework","Only HKEY_CLASSES_ROOT keys carry timestamps while all other hives store none of them"], correct:1, explanation:"Registry keys carry a LastWrite timestamp. Individual values do not each store their own time, so that option is wrong." },
  { id:70587, domain:4, level:2, question:"Why is the Windows event log channel Microsoft-Windows-TaskScheduler/Operational useful?", options:["It stores the plaintext of every command output produced by scheduled tasks on the host","It records the creation, registration, and execution of scheduled tasks, aiding persistence analysis","It is a full memory dump of the Task Scheduler service written at each system shutdown","It contains the encryption keys protecting the credentials stored for each scheduled task"], correct:2, explanation:"The channel logs task creation and execution for persistence analysis. It does not store command output or keys, so those are wrong." },
  { id:70588, domain:4, level:3, question:"An analyst finds bash_history is empty on a compromised Linux host. What is the most likely forensic interpretation?", options:["The system has never had any commands typed into any shell since it was first installed as commonly encountered in real casework","Bash cannot record history on Linux, so an empty file is normal and never suspicious","An empty file is proof the attacker never had interactive shell access to the machine","History may have been cleared, HISTFILE unset, or the shell configured to not record, warranting deeper review"], correct:3, explanation:"An empty history often signals clearing or disabling and warrants review. Claiming bash cannot record history is false, so that is wrong." },
  { id:70589, domain:4, level:1, question:"What is the primary evidentiary value of macOS Unified Logging for an examiner?", options:["It provides a centralized, queryable record of system and application events over time","It stores a full plaintext copy of every user password entered at the login window as commonly encountered in real casework","It is the only place macOS keeps the user's iCloud photos for offline examination","It contains the complete firmware image of the Mac's logic board for verification"], correct:0, explanation:"Unified Logging centralizes system/app events for querying. It does not store passwords or firmware, so those options are wrong." },
  { id:70590, domain:4, level:2, question:"Which browser artifact would most directly reveal search terms a user entered into a search engine?", options:["The favicon cache, which only stores the small icons displayed beside site titles","The URL history entries, whose query strings often contain the submitted search terms","The DNS resolver cache, which maps hostnames to IPs but not any query parameters","The prefetch file for the browser, which shows execution but not any typed queries as commonly encountered in real casework"], correct:1, explanation:"History URLs often embed search query strings. Favicons only store site icons, so that option is wrong." },
  { id:70591, domain:4, level:2, question:"In email forensics, what does the 'Return-Path' header typically indicate?", options:["The recipient's physical postal address to which undeliverable mail is physically returned as commonly encountered in real casework","The web page URL the sender visited immediately before composing the email message","The envelope sender address used for bounce handling, which may differ from the visible From","The encryption key needed to decrypt the message body when it was sent as protected"], correct:2, explanation:"Return-Path is the envelope sender for bounces, which can differ from From. It is not a decryption key, so that option is wrong." },
  { id:70592, domain:4, level:3, question:"An examiner wants to attribute a specific outbound email to a workstation. Which artifacts combine best?", options:["Only the recipient's reply, which proves receipt but not which machine sent the original","Only the email's font and color, which are cosmetic and identify no sending workstation","Only the subject line wording, which any user on any machine could have typed identically as commonly encountered in real casework","Local mail client store (PST/OST), Sent items, plus server SMTP logs showing the submitting host"], correct:3, explanation:"The local store, Sent items, and server SMTP logs attribute the send. The recipient's reply proves receipt, not the sender, so it is wrong." },
  { id:70593, domain:4, level:1, question:"What does a password 'dictionary attack' rely upon to succeed efficiently?", options:["A wordlist of likely passwords, testing each against the target hash or login prompt","Trying every possible character combination regardless of likelihood or word structure","A precomputed table of hashes that only works against unsalted stored password values","Tricking the user through a phishing message rather than any computation on hashes"], correct:0, explanation:"A dictionary attack tests a wordlist of likely passwords. Trying all combinations describes brute force, so that option is wrong." },
  { id:70594, domain:4, level:2, question:"Which tool is widely used to crack password hashes using GPU acceleration in forensic labs?", options:["Wireshark, which captures and analyzes network packets rather than cracking any hashes","Hashcat, which performs high-speed dictionary, mask, and brute-force attacks on many hash types","Autopsy, which is a disk-image analysis platform and does not perform hash cracking itself as commonly encountered in real casework","Nmap, which scans hosts for open ports and services but does not crack password hashes"], correct:1, explanation:"Hashcat is a GPU-accelerated hash cracker. Wireshark captures packets, not cracks hashes, so it is wrong." },
  { id:70595, domain:4, level:2, question:"What is the forensic importance of the Windows 'AppCompatCache' (ShimCache) entry order?", options:["Entries are always sorted alphabetically, so their order carries no temporal meaning at all as commonly encountered in real casework","Entries store the user's password history in the order the passwords were changed over time","The cache orders entries by execution recency on some versions, aiding recent-activity inference","The order reflects physical disk sector position and reveals nothing about program timing"], correct:2, explanation:"On some Windows versions ShimCache order reflects recency, aiding inference. It is not alphabetical, so that option is wrong." },
  { id:70596, domain:4, level:3, question:"An examiner recovers a hibernation file. What is the MOST valuable action to extract volatile evidence?", options:["Delete the file immediately because hibernation files never contain useful forensic data as commonly encountered in real casework","Print the raw bytes to paper for manual review since no tool can interpret the format","Overwrite it with zeros to preserve the disk, discarding the volatile memory it contains","Convert hiberfil.sys to a raw memory image and analyze it with Volatility for processes and artifacts"], correct:3, explanation:"Converting hiberfil.sys to a raw image enables Volatility analysis. Deleting it would destroy volatile evidence, so that is wrong." },
  { id:70597, domain:4, level:1, question:"What does the term 'artifact' generally mean in operating-system forensics?", options:["A trace or record left by user or system activity that has evidentiary value to an examiner","A hardware component such as a hard drive or memory module physically seized as evidence as commonly encountered in real casework","A cryptographic key used exclusively to sign the examiner's final investigative report","A courtroom exhibit label attached to physical evidence before it is admitted at trial"], correct:0, explanation:"An artifact is an activity trace with evidentiary value. A physical drive is hardware, not an artifact record, so that option is wrong." },
  { id:70598, domain:4, level:2, question:"Which Windows artifact best shows the folders and files pinned or recently used within a specific application?", options:["The pagefile.sys, which holds paged memory fragments but no per-application recent lists","The application's Jump List files stored under AutomaticDestinations in the user's profile","The BIOS setup, which stores boot device order but no application recent-file data at all as commonly encountered in real casework","The DNS cache, which records resolved hostnames rather than any recently used files"], correct:1, explanation:"Jump Lists (AutomaticDestinations) show per-app recent/pinned items. The pagefile has no such lists, so that option is wrong." },
  { id:70599, domain:4, level:2, question:"Why is the Windows registry MRUListEx value important within many MRU keys?", options:["It encrypts the MRU entries so that only the currently logged-on user can ever read them","It stores the total number of times the machine has been rebooted since installation","It defines the order of most-recently-used entries, revealing the sequence of user actions","It contains the antivirus quarantine list rather than any most-recently-used ordering data"], correct:2, explanation:"MRUListEx defines the ordering of MRU entries, showing action sequence. It is not an encryption mechanism, so that option is wrong." },
  { id:70600, domain:4, level:3, question:"An examiner must determine which user deleted a file on a multi-user Windows system. What is strongest?", options:["Assuming the administrator did it because administrators have permission to delete any file","Guessing based on which user logged in most recently to the machine that day overall","Relying only on the file's modified timestamp, which reflects content edits and not deletion","Correlating the $I record in that user's $Recycle.Bin SID folder with logon session times"], correct:3, explanation:"The $I record lives in the deleting user's SID folder, correlating with logons. Assuming the admin did it is unfounded, so that is wrong." },
  { id:70601, domain:4, level:1, question:"What is the purpose of Windows 'UserAssist' ROT13 encoding of value names?", options:["It is a simple obfuscation of the executed program paths, easily decoded during analysis","It strongly encrypts the entries so that no forensic tool can ever recover the program names","It compresses the entries to save disk space at the cost of losing the program path data","It signs the entries cryptographically to prove the operating system wrote each of them"], correct:0, explanation:"UserAssist uses ROT13, a trivial obfuscation easily decoded. It is not strong encryption, so that option is wrong." },
  { id:70602, domain:4, level:2, question:"Which Linux artifact would most directly show services configured to start automatically at boot?", options:["The /proc/uptime file, which only reports how long the system has been running currently","systemd unit files and 'systemctl list-unit-files', which reveal enabled boot-time services","The /dev/sda device node, which represents a disk and lists no service startup configuration","The ~/.bash_logout script, which only runs when an interactive login shell is closing"], correct:1, explanation:"systemd unit files show enabled boot services. /proc/uptime only reports runtime, not services, so it is wrong." },
  { id:70603, domain:4, level:2, question:"What does the presence of an unfamiliar entry in /etc/passwd or /etc/shadow potentially indicate?", options:["That the Linux kernel automatically created a temporary account during the last update","That an attacker may have added a backdoor account to maintain persistent access to the host","That the account is guaranteed legitimate because only root can ever edit these two files","That the machine's hardware clock has drifted and created a spurious account by accident"], correct:2, explanation:"An unfamiliar account can be an attacker backdoor. It is not guaranteed legitimate merely because root can edit the file, so that is wrong." },
  { id:70604, domain:4, level:3, question:"An analyst examines a memory image and wants to recover typed strings or clipboard content. Which is best?", options:["Reading only the on-disk registry, which does not capture transient in-memory typed strings as commonly encountered in real casework","Trusting the file system journal alone, which logs metadata changes but not typed text","Reviewing only the prefetch files, which prove execution but hold no typed string content","Running strings and clipboard/edit-related Volatility plugins against the captured memory image"], correct:3, explanation:"Strings and clipboard plugins on the memory image can recover typed content. The registry does not hold transient typed strings, so that is wrong." },
  { id:70605, domain:4, level:1, question:"What does the Windows 'RecentDocs' registry key primarily record?", options:["Documents and files the user recently opened, organized by file extension subkeys","The full contents of each recently opened document for offline recovery when deleted","The user's saved website passwords synced from the signed-in browser profile store","The BIOS boot sequence and the order in which storage devices are polled at startup"], correct:0, explanation:"RecentDocs lists recently opened files by extension. It does not store full document contents, so that option is wrong." },
  { id:70606, domain:4, level:2, question:"Which macOS artifact would reveal applications that recently launched or were used by a user?", options:["The /System/Library/Kernels folder, which only holds the compiled kernel binaries themselves","LaunchServices and per-user plist artifacts such as com.apple.recentitems recording recent apps and files","The /dev/disk0 node, which represents the physical disk and records no application usage data as commonly encountered in real casework","The EFI firmware store, which holds boot settings rather than any application launch history"], correct:1, explanation:"LaunchServices and recentitems plists record recent apps/files. /dev/disk0 is just the disk node, so that option is wrong." },
  { id:70607, domain:4, level:2, question:"Why might an examiner analyze the Chrome 'Top Sites' or 'Visited Links' data?", options:["Because it stores the user's saved passwords for each of the most frequently visited sites as commonly encountered in real casework","Because it is the only artifact that captures the browser process memory during each visit","To identify frequently visited websites, corroborating browsing patterns with the main history","Because it records the physical location of the device at the time each site was visited"], correct:2, explanation:"Top Sites/Visited Links corroborate frequent browsing patterns. They do not store passwords, so that option is wrong." },
  { id:70608, domain:4, level:3, question:"An investigator needs to prove an email attachment was saved and later opened on a Windows host. What is strongest?", options:["Only the email's Received headers, which show delivery but not local saving or opening","Only the mail server log, which records transport but not local file save or open events","Only the antivirus definition date, which is unrelated to saving or opening any attachment as commonly encountered in real casework","The saved file's LNK/RecentDocs entries plus Prefetch of the handling application and MFT timestamps"], correct:3, explanation:"LNK/RecentDocs, Prefetch, and MFT timestamps prove local save and open. Received headers show delivery only, so that is wrong." },
  { id:70609, domain:4, level:1, question:"What does the acronym MRU stand for in Windows registry forensics?", options:["Most Recently Used, referring to lists of recently accessed files, paths, or commands","Memory Resident Unit, describing a hardware component that caches CPU instructions","Mandatory Registry Update, a Microsoft policy for pushing security patches to hives","Master Recovery Utility, a tool used to rebuild corrupted registry hives after a crash"], correct:0, explanation:"MRU means Most Recently Used. It is not a hardware unit or a patch policy, so those options are wrong." },
  { id:70610, domain:4, level:2, question:"Which artifact best helps reconstruct which network shares a Windows user connected to?", options:["The BIOS setup screen, which stores boot order and holds no network share history","The MountPoints2 key under NTUSER.DAT, which records mapped drives and connected network shares","The desktop.ini file, which only customizes folder appearance and stores no share data","The thumbs.db file, which caches image thumbnails and records nothing about network shares as commonly encountered in real casework"], correct:1, explanation:"MountPoints2 records mapped drives and shares per user. The BIOS setup holds no such history, so it is wrong." },
  { id:70611, domain:4, level:2, question:"What does the systemd journal's ability to store binary, indexed logs mean for examiners?", options:["Logs cannot be read at all without the original signing key generated at install time","Logs are permanently encrypted and require a court order to the vendor to decrypt them","Logs must be queried with journalctl and can include structured fields, boot IDs, and metadata","Logs are automatically deleted the instant a single field within any entry is ever changed as commonly encountered in real casework"], correct:2, explanation:"The journal is queried via journalctl with structured metadata. It is not permanently encrypted, so that option is wrong." },
  { id:70612, domain:4, level:3, question:"An examiner sees a scheduled task pointing to a script in a temp folder on Windows. What is the best next step?", options:["Immediately delete the task since anything in a temp folder is always malicious by definition as commonly encountered in real casework","Ignore it because scheduled tasks in temp folders are always legitimate system operations","Reboot the machine to see whether the task disappears, treating that as proof of its intent","Examine the task XML, the referenced script, and TaskScheduler event logs to assess persistence and behavior"], correct:3, explanation:"Examining the XML, script, and logs assesses intent and persistence. Assuming it is always malicious or always legitimate is wrong." },
  { id:70613, domain:4, level:1, question:"What is the primary function of RAM (memory) acquisition in an investigation?", options:["To capture volatile data such as running processes, network connections, and in-memory keys","To permanently wipe the system's disk so that no residual data can ever be recovered","To reinstall the operating system from a clean image before analysis of the disk begins as commonly encountered in real casework","To physically clone the hard drive sector by sector for later bit-stream verification"], correct:0, explanation:"RAM acquisition captures volatile data. Cloning the hard drive is disk imaging, a different task, so that option is wrong." },
  { id:70614, domain:4, level:2, question:"Which Firefox file stores cookies for the user's profile?", options:["The places.sqlite file, which actually stores browsing history and bookmarks, not cookies","The cookies.sqlite file, an SQLite database in the profile holding the browser's cookies","The prefs.js file, which stores browser preferences and settings rather than any cookies","The compatibility.ini file, which records the profile's version and holds no cookie data"], correct:1, explanation:"Firefox stores cookies in cookies.sqlite. places.sqlite holds history/bookmarks, not cookies, so that option is wrong." },
  { id:70615, domain:4, level:2, question:"Why is examining email X-Originating-IP or the earliest Received line useful?", options:["Because it reveals the recipient's saved contacts list embedded within the header block","Because it stores the message subject in encoded form for later integrity verification","It can reveal the IP address of the sender's originating client or first submission server","Because it contains the sender's plaintext password used to authenticate to the mail server"], correct:2, explanation:"These fields can reveal the originating IP. They do not contain the sender's password, so that option is wrong." },
  { id:70616, domain:4, level:3, question:"An examiner wants to distinguish a genuinely deleted file from one merely moved on NTFS. What helps most?", options:["Only the file's icon appearance, which is identical whether the file was moved or deleted as commonly encountered in real casework","Only the desktop wallpaper timestamp, which is cosmetic and unrelated to file operations","Only the DNS cache, which records name resolutions and nothing about file move or delete","Analyzing MFT entry flags, the USN journal ($UsnJrnl), and $Recycle.Bin $I records together"], correct:3, explanation:"MFT flags, the USN journal, and $I records distinguish delete vs move. The file icon reveals nothing here, so that option is wrong." },
  { id:70617, domain:4, level:1, question:"What does the Windows 'TypedURLs' registry key record?", options:["URLs the user typed directly into the Internet Explorer or Edge legacy address bar","Every URL ever visited across all browsers including full page content for each site","The saved passwords for every website the user logged into using any browser at all","The DNS server addresses configured on each of the machine's network adapters currently"], correct:0, explanation:"TypedURLs records addresses typed into the IE/legacy Edge bar. It does not store passwords, so that option is wrong." },
  { id:70618, domain:4, level:2, question:"Which Volatility plugin dumps a process's executable image from memory for further analysis?", options:["The netscan plugin, which enumerates network connections rather than dumping executables as commonly encountered in real casework","The procdump (or windows.dumpfiles) plugin, which extracts a process's executable from memory","The hivelist plugin, which locates registry hives in memory but dumps no process image","The pstree plugin, which shows process parent-child relationships but extracts no binary"], correct:1, explanation:"procdump/dumpfiles extract the process executable. netscan lists connections, not executables, so that option is wrong." },
  { id:70619, domain:4, level:2, question:"What is the forensic relevance of the Linux /var/log/wtmp and /var/log/btmp files?", options:["They store the kernel command line and boot parameters used at each system startup event as commonly encountered in real casework","They contain the full text of every email delivered to local users on the Linux host","wtmp records successful login sessions and btmp records failed login attempts on the host","They hold the encrypted password hashes for all accounts defined on the Linux system"], correct:2, explanation:"wtmp logs successful logins and btmp failed attempts. Password hashes live in /etc/shadow, so that option is wrong." },
  { id:70620, domain:4, level:3, question:"An examiner wants to confirm which process opened a suspicious network port in a memory image. What is best?", options:["Reading only the on-disk firewall rules, which define policy but not live open connections","Trusting only the prefetch run count, which shows execution frequency but no port ownership","Reviewing only the desktop shortcuts, which have no relationship to open network ports","Using netscan to map the local port to a PID, then pslist/cmdline to identify that process"], correct:3, explanation:"netscan maps a port to a PID, then pslist/cmdline identify the process. Firewall rules define policy, not ownership, so that is wrong." },
  { id:70621, domain:4, level:1, question:"What does the term 'volatile data' mean in the context of live forensics?", options:["Data that is lost when the system loses power, such as RAM contents and open connections","Data permanently written to disk that survives reboots and power cycles indefinitely","Data that has been encrypted and therefore cannot be read without the proper key","Data that has been digitally signed to prove its integrity throughout an investigation as commonly encountered in real casework"], correct:0, explanation:"Volatile data is lost on power loss, like RAM. Data written to disk that survives reboots is non-volatile, so that option is wrong." },
  { id:70622, domain:4, level:2, question:"Which Windows artifact would best reveal that a program was executed from a USB drive?", options:["The desktop.ini on the USB drive, which only customizes how the drive's folder appears","Prefetch and ShimCache entries showing the executable path referencing the removable volume","The BIOS boot order, which controls startup devices but records no per-program execution as commonly encountered in real casework","The DNS cache, which stores hostname resolutions and nothing about USB program execution"], correct:1, explanation:"Prefetch/ShimCache paths can reference the USB volume, showing execution. desktop.ini only styles the folder, so it is wrong." },
  { id:70623, domain:4, level:2, question:"Why is the macOS knowledgeC.db database valuable in behavioral forensics?", options:["Because it stores the user's iCloud password in plaintext for offline recovery by examiners as commonly encountered in real casework","Because it holds a byte-for-byte copy of RAM taken whenever the Mac goes to sleep mode","It records device usage events such as app usage, activity, and focus over time via the Knowledge store","Because it contains the complete Safari cache of every web page the user has ever viewed"], correct:2, explanation:"knowledgeC.db records device/app usage events over time. It does not store the iCloud password, so that option is wrong." },
  { id:70624, domain:4, level:3, question:"An examiner must determine whether a downloaded executable was actually run on a Windows host. Which is strongest?", options:["Only the browser download record, which proves the file arrived but not that it executed as commonly encountered in real casework","Only the file's presence on disk, which shows it was saved but not that it was launched","Only the file's digital signature, which attests to the publisher but not to execution","Prefetch and Amcache entries for the executable, corroborated by process-creation event 4688"], correct:3, explanation:"Prefetch, Amcache, and event 4688 confirm execution. A download record only proves arrival, not execution, so that is wrong." },
  { id:70625, domain:4, level:1, question:"What does the Windows Event Log file extension .evtx indicate?", options:["The modern XML-based binary event log format introduced with Windows Vista and later","A plaintext comma-separated log that any text editor can open and edit directly on disk","An encrypted archive requiring the domain administrator's key to open for any analysis","A memory dump of the event log service captured at the moment of each system crash"], correct:0, explanation:".evtx is the modern binary XML event log format. It is not a plaintext CSV, so that option is wrong." },
  { id:70626, domain:4, level:2, question:"Which artifact helps establish the last time a user interactively logged onto a Windows workstation?", options:["The BIOS real-time clock reading, which shows current time but not any prior logon time","Security Event ID 4624 logon records combined with the account's registry profile load time","The printer spooler queue, which lists print jobs but records no interactive logon times as commonly encountered in real casework","The pagefile.sys size, which reflects memory pressure but not any user logon activity"], correct:1, explanation:"Event 4624 plus profile load time establish logon. The BIOS clock only shows current time, so that option is wrong." },
  { id:70627, domain:4, level:2, question:"Why do investigators examine the Linux /home/user/.ssh/known_hosts file?", options:["Because it stores the user's private SSH key used to authenticate to remote servers as commonly encountered in real casework","Because it records the plaintext passwords the user typed during each SSH session","It records hosts the user connected to over SSH, helping map outbound remote activity","Because it contains the full command history of every SSH session the user opened"], correct:2, explanation:"known_hosts records SSH servers connected to. It holds host keys, not private keys or passwords, so those options are wrong." },
  { id:70628, domain:4, level:3, question:"An analyst must recover deleted browser history that the user cleared. What is the MOST reliable approach?", options:["Assuming the history is gone forever the instant the user clicks the clear-history button","Reading only the current History database, which by definition no longer holds cleared rows as commonly encountered in real casework","Trusting only the DNS cache, which is small, volatile, and clears frequently on its own","Carving free space in the History SQLite file and searching pagefile/unallocated space for URL fragments"], correct:3, explanation:"Carving SQLite free space and unallocated areas can recover cleared URLs. The current DB no longer holds them, so relying on it is wrong." },
  { id:70629, domain:4, level:1, question:"What is the purpose of a write blocker during operating-system forensic acquisition?", options:["To prevent any changes to the source evidence media while it is being read and imaged","To speed up the imaging process by compressing the data as it is copied from the disk","To crack the encryption on a protected volume before the image is created from it","To automatically classify recovered files as relevant or irrelevant during acquisition"], correct:0, explanation:"A write blocker prevents changes to source media. It does not crack encryption, so that option is wrong." },
  { id:70630, domain:4, level:2, question:"Which artifact best shows that a Windows user searched for a term using the Start menu or Explorer?", options:["The BIOS setup, which stores boot configuration and records no search queries at all as commonly encountered in real casework","The WordWheelQuery key under NTUSER.DAT, which records Explorer search-box query terms","The hosts file, which maps hostnames to IP addresses and records no search activity","The pagefile header, which describes swap layout but stores no user search queries"], correct:1, explanation:"WordWheelQuery records Explorer search terms. The BIOS setup stores no queries, so that option is wrong." },
  { id:70631, domain:4, level:2, question:"What does analysis of a PST file's deleted-items and free space potentially recover?", options:["The Exchange server's administrator credentials used to provision the original mailbox as commonly encountered in real casework","The physical serial number of the drive on which the PST file was originally created","Deleted email messages, attachments, and calendar items still resident in unused blocks","The BIOS firmware of the workstation where Outlook was installed and configured"], correct:2, explanation:"PST free space can retain deleted messages and attachments. It does not store the drive serial number, so that option is wrong." },
  { id:70632, domain:4, level:3, question:"An examiner suspects a fileless malware attack. Which artifact source is MOST likely to yield evidence?", options:["Only the on-disk executable inventory, which fileless malware specifically avoids populating as commonly encountered in real casework","Only the browser download history, which fileless techniques generally do not rely upon","Only the printer spooler queue, which has no relationship to in-memory malicious code","Memory analysis with Volatility plus PowerShell/WMI event logs and script block logging entries"], correct:3, explanation:"Memory analysis and PowerShell/WMI logs catch fileless activity. An on-disk executable inventory misses it by design, so that is wrong." },
  { id:70633, domain:4, level:1, question:"What does the Windows Prefetch layout store to speed up application launches?", options:["References to files and directories the application accessed during its first ten seconds","The complete source code of the application recompiled for the current processor model","The user's saved credentials for any online service the application connects to at launch","A full memory dump of the application taken at the moment it was last closed by the user"], correct:0, explanation:"Prefetch stores references to files/dirs used at startup. It does not store source code, so that option is wrong." },
  { id:70634, domain:4, level:2, question:"Which macOS log or database records Wi-Fi and network association history useful in forensics?", options:["The /System/Library/Kernels directory, which only stores kernel binaries, not network history as commonly encountered in real casework","The com.apple.wifi plist and Unified Logging entries, which record known networks and associations","The /dev/null device, which discards all input and stores no network association records","The EFI NVRAM boot settings, which control startup but record no Wi-Fi association data"], correct:1, explanation:"Wi-Fi plists and Unified Logging record network associations. /dev/null stores nothing, so that option is wrong." },
  { id:70635, domain:4, level:2, question:"Why is the Windows 'BAM' (Background Activity Moderator) key useful to an examiner?", options:["Because it stores the plaintext passwords of background services running on the system","Because it holds a full packet capture of every background network connection made","It records the last execution time of programs run by a user, supporting execution timelines","Because it contains the antivirus quarantine list of files removed during background scans as commonly encountered in real casework"], correct:2, explanation:"BAM records last-run times per user, aiding timelines. It does not store passwords or packet captures, so those are wrong." },
  { id:70636, domain:4, level:3, question:"An examiner must correlate activity across time zones during an incident. What is the best practice?", options:["Recording every timestamp in the examiner's local time without noting any offset used","Ignoring time zones entirely because forensic tools always agree on a single time value","Converting some artifacts and leaving others unconverted, mixing formats within one timeline","Normalizing all timestamps to UTC and documenting the source time zone of each artifact"], correct:3, explanation:"Normalizing to UTC with documented source zones avoids confusion. Ignoring time zones invites error, so that option is wrong." },
  { id:70637, domain:4, level:1, question:"What is the primary use of the 'strings' utility in application and memory forensics?", options:["To extract human-readable text sequences from binary files or memory images for review","To encrypt a suspect file so that its contents cannot be read without a decryption key","To permanently delete sensitive text from a disk so it can never be recovered again","To compile source code found on the suspect system into an executable for testing"], correct:0, explanation:"strings extracts readable text from binaries/memory. It does not encrypt or delete data, so those options are wrong." },
  { id:70638, domain:4, level:2, question:"Which browser artifact records the number of times and last time a specific page was visited?", options:["The favicon cache, which stores site icons but no visit counts or timestamps at all","The history database's visit_count and last_visit_time fields for each recorded URL entry","The cookies store, which holds session tokens but no per-page visit count information as commonly encountered in real casework","The prefetch file, which is a Windows execution artifact unrelated to web page visits"], correct:1, explanation:"History fields visit_count and last_visit_time record visits. Favicons only store icons, so that option is wrong." },
  { id:70639, domain:4, level:2, question:"What is the significance of an email's 'Content-Type: multipart/mixed' header?", options:["It proves the message was encrypted end-to-end and cannot be read without a key","It stores the sender's IP address encoded within the content-type boundary string value","The message contains multiple parts such as a body plus one or more attached files","It indicates the message was digitally signed by the sender's corporate mail gateway"], correct:2, explanation:"multipart/mixed indicates a body plus attachments. It does not by itself imply encryption, so that option is wrong." },
  { id:70640, domain:4, level:3, question:"An examiner needs to prove a specific user account executed a PowerShell command. What is strongest?", options:["Only the file system timestamp of powershell.exe, which reflects installation, not any run","Only the presence of PowerShell on the system, which every modern Windows install includes","Only the desktop wallpaper of the account, which is cosmetic and proves no command execution as commonly encountered in real casework","Script block logging (Event 4104) and 4688 process creation tied to that user's logon session"], correct:3, explanation:"Event 4104 script blocks and 4688 tied to the logon prove execution by the user. powershell.exe's timestamp reflects install, so that is wrong." },
  { id:70641, domain:4, level:1, question:"What does the acronym VSS refer to in Windows forensics?", options:["Volume Shadow Copy Service, which creates point-in-time snapshots useful for recovering prior data","Very Secure Storage, an encrypted container used to protect the examiner's working notes as commonly encountered in real casework","Virtual System Scheduler, a component that queues background tasks on the Windows kernel","Verified Signature Store, a database of trusted publisher certificates used by the OS"], correct:0, explanation:"VSS is the Volume Shadow Copy Service for snapshots. It is not an encrypted note container, so that option is wrong." },
  { id:70642, domain:4, level:2, question:"Why are Volume Shadow Copies valuable in an investigation?", options:["They store the user's login password history in an easily decrypted plaintext format","They can contain earlier versions of files and registry hives, revealing prior system states","They are the only place Windows keeps the current running process list after shutdown","They hold a full packet capture of all network traffic since the machine was installed as commonly encountered in real casework"], correct:1, explanation:"Shadow copies preserve prior file/registry versions. They do not store password history in plaintext, so that option is wrong." },
  { id:70643, domain:4, level:2, question:"Which Linux artifact would reveal that a user escalated privileges using sudo?", options:["The /proc/cpuinfo file, which describes the processor and logs no privilege escalation as commonly encountered in real casework","The /etc/hostname file, which stores the machine name and records no sudo activity","Entries in /var/log/auth.log (or secure) recording sudo command invocations by that user","The /dev/sda device node, which represents the disk and logs no sudo command usage"], correct:2, explanation:"auth.log/secure records sudo invocations. /proc/cpuinfo describes the CPU, not privilege use, so that option is wrong." },
  { id:70644, domain:4, level:3, question:"An examiner recovers a suspicious DLL from a memory image. Which step best determines if it was injected?", options:["Comparing only the DLL's file name against a list of known good Windows library names","Trusting only the DLL's version resource, which malware can forge to appear legitimate as commonly encountered in real casework","Checking only the DLL's on-disk creation date, which reflects copy time, not injection","Using ldrmodules and malfind to compare loaded modules and detect unlinked or hidden mappings"], correct:3, explanation:"ldrmodules and malfind reveal unlinked/injected modules. A version resource can be forged, so relying on it is wrong." },
  { id:70645, domain:4, level:1, question:"What is the forensic value of the Windows 'setupapi.dev.log' file?", options:["It records device installation events, including the first time devices such as USB were connected","It stores the plaintext passwords of every user who has logged into the workstation as commonly encountered in real casework","It contains a full memory dump of the driver stack captured at each device removal","It holds the browsing history of every browser installed on the Windows machine"], correct:0, explanation:"setupapi.dev.log records device installation and first-connect times. It does not store passwords, so that option is wrong." },
  { id:70646, domain:4, level:2, question:"Which artifact would best show which documents were recently edited in Microsoft Word?", options:["The pagefile.sys, which holds memory fragments but no application-specific recent list as commonly encountered in real casework","Word's MRU entries under the Office registry keys plus the associated Jump List for Word","The BIOS setup, which stores boot order and records no application document history","The DNS cache, which stores hostname resolutions rather than recently edited documents"], correct:1, explanation:"Office MRU keys and Word's Jump List show recent documents. The pagefile has no such list, so that option is wrong." },
  { id:70647, domain:4, level:2, question:"Why is the 'Authentication-Results' header important when validating an email's legitimacy?", options:["Because it stores the sender's mailbox password so the receiver can verify the account as commonly encountered in real casework","Because it contains the full message body signed to guarantee no content was altered","It records the outcome of SPF, DKIM, and DMARC checks performed by the receiving server","Because it lists every recipient's IP address to prove the message reached each inbox"], correct:2, explanation:"Authentication-Results reports SPF/DKIM/DMARC outcomes. It does not contain the sender's password, so that option is wrong." },
  { id:70648, domain:4, level:3, question:"An examiner must determine when a Windows account's password was last changed for a timeline. What is best?", options:["Reading only the current time from the BIOS, which reflects now, not any password change","Guessing based on when the user last logged in, which is unrelated to password change time as commonly encountered in real casework","Assuming the password never changed because the account still functions normally today","Examining the SAM hive's account F/V structures or Event ID 4723/4724 password-change records"], correct:3, explanation:"SAM structures and events 4723/4724 record password changes. Logon time is unrelated to password change, so that option is wrong." },
  { id:70649, domain:4, level:1, question:"What does the Windows 'Recent' folder (AppData\\Roaming\\Microsoft\\Windows\\Recent) contain?", options:["LNK shortcut files pointing to recently opened documents and folders for the user","The full contents of every recently opened document stored for offline recovery use","The saved passwords for every website the user logged into with any installed browser","A complete registry backup taken each time the user opens a new document or folder"], correct:0, explanation:"The Recent folder holds LNK shortcuts to recent items. It does not store full document contents, so that option is wrong." },
  { id:70650, domain:4, level:2, question:"Which artifact best helps determine the SID-to-username mapping on a Windows system?", options:["The pagefile.sys, which holds memory fragments but no reliable SID-to-username mapping as commonly encountered in real casework","The SAM hive and the ProfileList key under SOFTWARE, which map SIDs to account names and profiles","The BIOS setup, which stores boot configuration and holds no account name mapping data","The DNS cache, which resolves hostnames to IPs and stores no SID-to-username mapping"], correct:1, explanation:"SAM and ProfileList map SIDs to accounts/profiles. The pagefile has no reliable mapping, so that option is wrong." },
  { id:70651, domain:4, level:2, question:"What is the forensic relevance of the Linux .viminfo or editor history files?", options:["They store the kernel version and boot parameters used during the most recent startup as commonly encountered in real casework","They contain the encrypted password hashes for every user account on the Linux host","They can reveal recently edited files, search patterns, and command history within the editor","They hold a full memory dump of the editor process captured whenever a file is saved"], correct:2, explanation:".viminfo reveals recently edited files and editor history. It does not store password hashes, so that option is wrong." },
  { id:70652, domain:4, level:3, question:"An examiner needs to establish the sequence of programs a user ran during a session. What combination is best?", options:["Only the BIOS boot log, which records hardware initialization but no user program sequence","Only the current process list, which shows running programs but not the full session sequence as commonly encountered in real casework","Only the desktop wallpaper history, which is cosmetic and reveals no program execution order","UserAssist, Prefetch last-run times, BAM, and Amcache correlated into a single execution timeline"], correct:3, explanation:"UserAssist, Prefetch, BAM, and Amcache together sequence execution. The BIOS boot log shows no user programs, so that option is wrong." },
  { id:70653, domain:4, level:1, question:"What is the primary purpose of hashing a forensic image after acquisition?", options:["To verify integrity by proving the image has not changed since it was first acquired","To compress the image so that it occupies less space on the examiner's storage media","To encrypt the image so that only the examiner can open it during the investigation","To index the image's contents so that keyword searches run faster during analysis"], correct:0, explanation:"Hashing verifies image integrity over time. It neither compresses nor encrypts the image, so those options are wrong." },
  { id:70654, domain:4, level:2, question:"Which Chrome artifact stores autofill data such as saved form field entries?", options:["The History database, which stores visited URLs and timestamps rather than form autofill data","The Web Data SQLite database, which stores autofill form entries and saved payment profiles","The Cookies store, which holds session tokens but no saved form autofill values at all","The Bookmarks file, which stores saved page shortcuts and no autofill information whatsoever"], correct:1, explanation:"Web Data holds autofill and payment info. The History DB stores URLs, not autofill, so that option is wrong." },
  { id:70655, domain:4, level:2, question:"Why is examining email attachments' embedded metadata forensically useful?", options:["Because attachment metadata always contains the sender's mail server login credentials","Because it stores the recipient's IP address needed to prove the message was delivered","Document metadata may reveal authors, creation dates, and software, aiding attribution and timelines","Because it holds a full copy of the mail server transaction log for the message in question as commonly encountered in real casework"], correct:2, explanation:"Document metadata can reveal authors and dates for attribution. It does not contain server credentials, so that option is wrong." },
  { id:70656, domain:4, level:3, question:"An examiner must prove a specific file existed on a system that has since been wiped. What is strongest?", options:["Assuming the file never existed because it cannot be found on the current live file system as commonly encountered in real casework","Relying only on the suspect's verbal statement about whether the file was ever present","Checking only the current directory listing, which by definition omits any wiped file","Cross-referencing MFT residuals, ShimCache, Amcache, LNK, and shadow copies for the file's path and hash"], correct:3, explanation:"MFT residuals, ShimCache, Amcache, LNK, and shadow copies can prove prior existence. A current listing omits wiped files, so relying on it is wrong." },
  { id:70657, domain:4, level:1, question:"What does the Windows 'Recycle Bin' SID subfolder structure indicate to an examiner?", options:["Which user account deleted a given file, since items are grouped under that user's SID","The physical disk sector where each deleted file's contents are currently stored on disk","The encryption key needed to restore each deleted file to its original location on disk","The BIOS boot order in effect at the moment each file was moved to the Recycle Bin"], correct:0, explanation:"SID subfolders show which user deleted a file. They do not store encryption keys, so that option is wrong." },
  { id:70658, domain:4, level:2, question:"Which memory artifact helps identify malware persistence via injected code in legitimate processes?", options:["The on-disk registry Run key alone, which shows autostart entries but not in-memory injection as commonly encountered in real casework","malfind output, which flags memory regions with executable, private pages typical of code injection","The prefetch run count, which indicates execution frequency but not any code injection","The desktop.ini file, which customizes folder appearance and reveals no injected code"], correct:1, explanation:"malfind flags injected executable private pages. The Run key shows autostart, not in-memory injection, so that option is wrong." },
  { id:70659, domain:4, level:2, question:"What does the Linux 'lastb' command reveal that complements the 'last' command?", options:["It shows the current CPU load average rather than any login-related information at all","It lists the mounted filesystems on the host rather than any authentication attempt data as commonly encountered in real casework","It displays failed login attempts recorded in btmp, complementing successful logins from wtmp","It prints the kernel ring buffer messages, which are unrelated to login attempt history"], correct:2, explanation:"lastb shows failed logins from btmp. It does not print CPU load or the kernel ring buffer, so those options are wrong." },
  { id:70660, domain:4, level:3, question:"An examiner needs to determine which browser profile made a specific visit on a multi-profile Chrome install. What is best?", options:["Assuming the default profile made every visit regardless of how many profiles exist","Reading only the combined download folder, which does not attribute visits to any profile as commonly encountered in real casework","Trusting only the OS username, which does not distinguish among multiple Chrome profiles","Examining the History database within each profile subfolder to attribute the visit to a profile"], correct:3, explanation:"Each Chrome profile has its own History DB, attributing visits per profile. Assuming the default profile is unfounded, so that option is wrong." },
  { id:70661, domain:4, level:1, question:"What is the main forensic use of the Windows 'Amcache.hve' file?", options:["To identify programs that were present or executed, including their SHA-1 hashes and paths","To store the plaintext passwords for every user account configured on the workstation","To hold a full packet capture of the machine's network traffic for the current session","To keep a real-time copy of the running process list even after the system is powered off as commonly encountered in real casework"], correct:0, explanation:"Amcache identifies programs by hash and path. It does not store passwords, so that option is wrong." },
  { id:70662, domain:4, level:2, question:"Which artifact would help confirm a user connected an external hard drive versus a USB thumb drive?", options:["The BIOS setup screen, which stores boot device order but no external drive class data","The device descriptors under USBSTOR/Enum, which include the device class and vendor/product identifiers","The DNS cache, which maps hostnames to IPs and records no external storage device details","The pagefile header, which describes swap layout and holds no removable device information as commonly encountered in real casework"], correct:1, explanation:"USBSTOR/Enum descriptors reveal device class and IDs. The BIOS setup lacks this data, so that option is wrong." },
  { id:70663, domain:4, level:2, question:"Why might an examiner extract and analyze the pagefile.sys and swapfile.sys together?", options:["Because both files store the authoritative NTFS journal needed to rebuild the file system as commonly encountered in real casework","Because both are encrypted registry backups that Windows writes on every clean shutdown","They may hold paged-out memory fragments, including strings and process data from prior activity","Because both contain the complete browsing history of every browser installed on the host"], correct:2, explanation:"Both may hold paged-out memory fragments. They are not registry backups, so that option is wrong." },
  { id:70664, domain:4, level:3, question:"An examiner suspects an attacker used WMI for persistence on Windows. Where should they look first?", options:["Only the browser cache, which stores web resources unrelated to WMI persistence mechanisms","Only the Recycle Bin, which holds deleted files but no WMI subscription persistence data","Only the desktop shortcuts, which have no relationship to WMI event subscription persistence as commonly encountered in real casework","The WMI repository (OBJECTS.DATA) and WMI-Activity/Operational logs for permanent event subscriptions"], correct:3, explanation:"The WMI repository and WMI-Activity logs reveal subscription persistence. The browser cache is unrelated, so that option is wrong." },
  { id:70665, domain:4, level:1, question:"What does the Windows 'thumbcache' database primarily store?", options:["Cached thumbnail images of files the user viewed, retained even after the originals are deleted","The full-resolution originals of every image the user has ever opened on the system as commonly encountered in real casework","The user's saved passwords for photo-sharing websites accessed through the browser","A complete registry backup taken each time the user opens an image in Explorer"], correct:0, explanation:"Thumbcache stores viewed image thumbnails, surviving deletion. It does not store full-resolution originals, so that option is wrong." },
  { id:70666, domain:4, level:2, question:"Which artifact best reveals the programs that ran automatically when a specific user logged on?", options:["The BIOS boot order, which controls hardware startup but not per-user logon programs as commonly encountered in real casework","The user's Startup folder and HKCU Run keys, which define programs launched at that user's logon","The DNS cache, which resolves hostnames to IPs and lists no logon startup programs","The pagefile.sys, which holds memory fragments but no per-user logon startup entries"], correct:1, explanation:"The Startup folder and HKCU Run keys define per-user logon programs. The BIOS order is machine hardware, so that option is wrong." },
  { id:70667, domain:4, level:2, question:"What does the presence of an SMTP AUTH log entry on a mail server help establish?", options:["That the message body was encrypted end-to-end before leaving the sending mail client","That the recipient successfully opened and read the message in their mail client program as commonly encountered in real casework","That a specific account authenticated to send mail, aiding attribution of the outbound message","That the message was digitally signed with DKIM by the receiving organization's gateway"], correct:2, explanation:"SMTP AUTH entries show which account authenticated to send. They do not prove the recipient read the message, so that option is wrong." },
  { id:70668, domain:4, level:3, question:"An examiner needs to reconstruct a user's activity when only a memory image is available. What is best?", options:["Concluding no activity can be reconstructed because disk artifacts are entirely absent here as commonly encountered in real casework","Relying only on the process list, which shows what ran but not the broader user context","Reading only the network connections, which show endpoints but not documents or commands","Extracting processes, command lines, network connections, registry-in-memory, and strings for a combined picture"], correct:3, explanation:"Combining processes, command lines, connections, in-memory registry, and strings reconstructs activity. Claiming nothing can be recovered is wrong." },
  { id:70669, domain:4, level:1, question:"What is the purpose of the Linux /etc/shadow file in forensic terms?", options:["It stores hashed user passwords and password aging data, a target for credential analysis","It records the full command history for every user account across all interactive shells","It holds the kernel boot parameters applied at each startup of the Linux operating system","It contains a complete list of every file ever accessed by every user on the system"], correct:0, explanation:"/etc/shadow stores hashed passwords and aging data. It does not record command history, so that option is wrong." },
  { id:70670, domain:4, level:2, question:"Which artifact would best help determine when a Windows service was installed by an attacker?", options:["The BIOS setup, which stores boot configuration and records no service installation events as commonly encountered in real casework","Event ID 7045 in the System log, which records that a new service was installed with details","The DNS cache, which maps hostnames to IPs and logs no service installation activity","The Recycle Bin, which stores deleted files but no service installation timestamps at all"], correct:1, explanation:"Event 7045 records new service installation. The BIOS setup logs no such events, so that option is wrong." },
  { id:70671, domain:4, level:2, question:"Why is the macOS 'quarantine' extended attribute (com.apple.quarantine) forensically useful?", options:["Because it stores the plaintext password the user entered to download the quarantined file as commonly encountered in real casework","Because it holds a full memory dump of the downloading application at the time of download","It records where and when a file was downloaded, including the originating app and URL context","Because it contains the complete network packet capture of the download transaction itself"], correct:2, explanation:"The quarantine attribute records download source and time. It does not store passwords or packet captures, so those are wrong." },
  { id:70672, domain:4, level:3, question:"An examiner must confirm lateral movement via RDP between two Windows hosts. Which artifacts are strongest?", options:["Only the desktop wallpaper on each host, which is cosmetic and shows no remote connections as commonly encountered in real casework","Only the browser history on each host, which records web activity, not any RDP connections","Only the printer queue on each host, which lists print jobs but no remote desktop sessions","Logon type 10 events (4624), TerminalServices-RemoteConnectionManager logs, and bitmap/RDP cache artifacts"], correct:3, explanation:"Type-10 logons, RDP connection logs, and RDP cache confirm lateral movement. Wallpaper reveals nothing, so that option is wrong." },
  { id:70673, domain:4, level:1, question:"What does the term 'live acquisition' mean in operating-system forensics?", options:["Collecting evidence from a running system, including volatile data, before it is powered down","Imaging a powered-off disk after removing it from the machine and attaching a write blocker as commonly encountered in real casework","Recovering deleted files from unallocated space using a carving tool on a static image","Analyzing a printed report of the file system generated by the operating system at boot"], correct:0, explanation:"Live acquisition collects from a running system including volatile data. Imaging a powered-off disk is static acquisition, so that option is wrong." },
  { id:70674, domain:4, level:2, question:"Which artifact best shows the folders a user expanded and browsed in Explorer over time, including USB volumes?", options:["The pagefile.sys, which holds memory fragments but no persistent folder-browsing state records as commonly encountered in real casework","ShellBags stored in the user's USRCLASS.DAT and NTUSER.DAT, recording folder view and browse state","The BIOS setup, which stores boot order and records no folder-browsing information at all","The DNS cache, which resolves hostnames to IPs and holds no folder-browsing state data"], correct:1, explanation:"ShellBags in USRCLASS.DAT/NTUSER.DAT record folder browsing. The pagefile has no such persistent state, so that option is wrong." },
  { id:70675, domain:4, level:2, question:"Why do investigators parse the Windows 'AutomaticDestinations' and 'CustomDestinations' files?", options:["Because they store the plaintext passwords for the applications that created them on disk","Because they contain a full registry backup taken whenever a Jump List item is pinned","They are Jump List stores revealing recent and pinned files per application, aiding activity reconstruction","Because they hold the complete network packet capture generated by each pinned application as commonly encountered in real casework"], correct:2, explanation:"These files are Jump List stores of recent/pinned files per app. They do not store passwords, so that option is wrong." },
  { id:70676, domain:4, level:3, question:"An examiner needs to determine whether antiforensic timestomping occurred on key files. What is the strongest indicator?", options:["A file whose icon differs from other files of the same type in the same directory listing","A file that appears in the Recycle Bin, which merely indicates deletion, not timestamp tampering as commonly encountered in real casework","A file whose extension does not match its content, which suggests masquerading, not timestomping","Mismatches between $STANDARD_INFORMATION and $FILE_NAME timestamps, or sub-second values zeroed out"], correct:3, explanation:"SI/FN mismatches and zeroed sub-second values indicate timestomping. A differing icon is not a timestamp indicator, so that option is wrong." },
  { id:70677, domain:4, level:1, question:"What does the Volatility 'hivelist' plugin locate within a memory image?", options:["The in-memory registry hives and their virtual offsets for further registry analysis","The password hashes for every account, which require a different plugin to extract","The list of open network connections and their owning process identifiers on the host","The prefetch files present on the disk of the machine the memory was captured from"], correct:0, explanation:"hivelist locates in-memory registry hives. Extracting hashes requires hashdump, a different plugin, so that option is wrong." },
  { id:70678, domain:4, level:2, question:"Which artifact would best reveal that a user opened a document from a network share?", options:["The BIOS setup, which stores boot device order but no document-opening activity at all as commonly encountered in real casework","The LNK file for the document, whose target path and volume info can reference the UNC network path","The DNS cache alone, which maps hostnames to IPs but does not record document opening","The pagefile header, which describes swap layout and holds no document-opening records"], correct:1, explanation:"A LNK file's target path can reference the UNC share, showing the open. The BIOS setup records no such activity, so that option is wrong." },
  { id:70679, domain:4, level:2, question:"What is the significance of the 'MFT $LogFile' (transaction log) in NTFS forensics?", options:["It stores the user's login password history in a rolling encrypted format for recovery as commonly encountered in real casework","It holds the complete browsing history of every browser installed on the NTFS volume","It records recent metadata transactions, allowing reconstruction of recent file operations","It contains a full memory dump of the file system driver taken at each system shutdown"], correct:2, explanation:"$LogFile records recent metadata transactions for reconstructing operations. It does not store password history, so that option is wrong." },
  { id:70680, domain:4, level:3, question:"An examiner must attribute an email sent from a shared corporate account to an individual. What is strongest?", options:["Assuming the account owner sent it because their name is on the mailbox in the directory as commonly encountered in real casework","Relying only on the display name in the message, which anyone with access could have set","Trusting only the message subject, which any user of the shared account could have typed","Server SMTP AUTH logs, source IP correlation, and workstation artifacts placing a specific user at send time"], correct:3, explanation:"SMTP AUTH logs, source IP, and workstation artifacts attribute the send to a person. The display name proves nothing here, so that option is wrong." },
  { id:70681, domain:4, level:1, question:"What does the Windows 'AppData\\Local' folder typically contain that interests examiners?", options:["Machine-specific application data such as caches, browser profiles, and local program state","The complete Windows registry exported as text each time an application writes to it","The BIOS firmware image copied to disk during the operating system installation process as commonly encountered in real casework","The physical disk's partition table duplicated for redundancy by the operating system"], correct:0, explanation:"AppData\\Local holds machine-specific app data like caches and browser profiles. It is not a BIOS image, so that option is wrong." },
  { id:70682, domain:4, level:2, question:"Which artifact would best show the last time a user account accessed the system before a suspected compromise?", options:["The pagefile.sys, which holds memory fragments but no reliable last-access record per account","The lastLogon/lastLogonTimestamp attributes plus Security Event 4624 records for that account","The BIOS clock, which reports the current time but records no per-account access history","The DNS cache, which resolves hostnames to IPs and stores no account access timestamps"], correct:1, explanation:"lastLogon attributes and event 4624 show account access. The pagefile has no such record, so that option is wrong." },
  { id:70683, domain:4, level:2, question:"Why is the browser 'session restore' file forensically valuable?", options:["Because it stores the user's saved passwords for each tab that was open during the session","Because it holds a full memory dump of the browser process taken at each tab switch event","It can reveal tabs, URLs, and form data from the last session, including pages not yet in history","Because it contains the complete network packet capture of every request made in the session as commonly encountered in real casework"], correct:2, explanation:"Session restore reveals open tabs and URLs from the last session. It does not store saved passwords, so that option is wrong." },
  { id:70684, domain:4, level:3, question:"An examiner must determine whether data was exfiltrated via a cloud sync client. Which artifacts are strongest?", options:["Only the browser history, which may show cloud logins but not the actual synced file transfers as commonly encountered in real casework","Only the Recycle Bin, which holds deleted files but no cloud synchronization transfer records","Only the desktop wallpaper, which is cosmetic and reveals nothing about cloud sync activity","Sync client logs and databases, SRUM network usage per app, and file system timestamps of synced folders"], correct:3, explanation:"Sync client logs, SRUM per-app network usage, and folder timestamps reveal exfiltration. Browser history alone does not, so that option is wrong." },
  { id:70685, domain:4, level:1, question:"What is the primary use of the Windows Security Account Manager (SAM) hive in forensics?", options:["It stores local user account information and password hashes, useful for account and credential analysis","It records the browsing history of every browser installed on the Windows workstation","It holds the current running process list even after the machine has been powered off","It contains a full packet capture of the network traffic since the system was installed as commonly encountered in real casework"], correct:0, explanation:"The SAM hive stores local accounts and password hashes. It does not record browsing history, so that option is wrong." },
  { id:70686, domain:4, level:2, question:"Which artifact would best help confirm a specific application crashed and generated a report?", options:["The BIOS setup, which stores boot order and records no application crash information at all as commonly encountered in real casework","Windows Error Reporting (WER) files and the Application event log entries for the crashing program","The DNS cache, which resolves hostnames to IPs and holds no application crash records","The pagefile header, which describes swap layout but stores no application crash data"], correct:1, explanation:"WER files and Application log entries record crashes. The BIOS setup logs no crashes, so that option is wrong." },
  { id:70687, domain:4, level:2, question:"Why do investigators examine the '$UsnJrnl' change journal on NTFS?", options:["Because it stores the user's login password history in an easily decrypted plaintext format as commonly encountered in real casework","Because it holds the complete browsing history of every browser installed on the volume","It records file creation, deletion, and rename events, aiding reconstruction of recent file activity","Because it contains a full memory dump of the file system driver written at each shutdown"], correct:2, explanation:"$UsnJrnl logs file create/delete/rename events for activity reconstruction. It does not store password history, so that option is wrong." },
  { id:70688, domain:4, level:3, question:"An examiner needs to prove which specific USB device transferred files to a Windows host. What is strongest?", options:["Assuming the most recently connected device did it because it appears first in the device list","Relying only on the file's modified timestamp, which reflects content edits, not the transfer source as commonly encountered in real casework","Trusting only the desktop wallpaper date, which is cosmetic and unrelated to any file transfer","Correlating USBSTOR device serials, LNK volume serials of transferred files, and ShellBags for the device path"], correct:3, explanation:"USBSTOR serials, LNK volume serials, and ShellBags tie files to a specific device. Assuming the most recent device did it is unfounded, so that is wrong." },
  { id:70689, domain:4, level:1, question:"What does the Volatility 'hashdump' plugin extract from a Windows memory image?", options:["Local account password hashes recovered from the in-memory SAM and SYSTEM registry data","The complete browsing history of every browser that was running when memory was captured","The list of scheduled tasks configured on the disk of the machine that was imaged","The physical disk's partition table as it existed at the moment of memory acquisition"], correct:0, explanation:"hashdump extracts local password hashes from in-memory SAM/SYSTEM. It does not recover browsing history, so that option is wrong." },
  { id:70690, domain:4, level:2, question:"Which artifact best reveals that a user emptied the Recycle Bin at a particular time?", options:["The BIOS clock, which reports the current time but records no Recycle Bin emptying events","The disappearance of $I/$R files and USN journal delete entries for those items with timestamps","The DNS cache, which resolves hostnames to IPs and stores no Recycle Bin activity at all","The pagefile header, which describes swap layout and holds no Recycle Bin emptying records as commonly encountered in real casework"], correct:1, explanation:"Missing $I/$R plus USN delete entries reveal emptying with times. The BIOS clock records no such events, so that option is wrong." },
  { id:70691, domain:4, level:2, question:"Why is the macOS '.DS_Store' file sometimes useful in an investigation?", options:["Because it stores the user's iCloud password in plaintext for offline recovery by examiners as commonly encountered in real casework","Because it holds a full memory dump of the Finder process taken at each folder open event","It records folder view settings and can reveal names of files that once existed in that folder","Because it contains the complete network packet capture of the machine's Finder operations"], correct:2, explanation:".DS_Store records folder view settings and can reveal prior file names. It does not store passwords, so that option is wrong." },
  { id:70692, domain:4, level:3, question:"An examiner must determine whether a suspect accessed a file at a time they claim they were absent. What is strongest?", options:["Accepting the suspect's claim because file access times are never reliable in any scenario as commonly encountered in real casework","Relying only on the current directory listing, which shows presence but not access timing","Trusting only the file's icon, which is identical regardless of when the file was accessed","Correlating MFT access times, LNK/RecentDocs timestamps, and logon session records for that account"], correct:3, explanation:"MFT access times, LNK/RecentDocs, and logon records together establish access timing. Accepting the claim outright ignores evidence, so that is wrong." },
  { id:70693, domain:4, level:1, question:"What is the primary forensic value of examining browser cookies?", options:["They can reveal site sessions, logins, and tracking activity tied to specific websites and times","They store the complete source code of every web page the user visited for offline review as commonly encountered in real casework","They contain the user's operating-system login password in an easily decrypted format","They hold a full packet capture of every HTTPS request the browser made during a session"], correct:0, explanation:"Cookies reveal sessions, logins, and tracking. They do not store page source code, so that option is wrong." },
  { id:70694, domain:4, level:2, question:"Which artifact best helps determine which user was active at the console at a specific moment?", options:["The BIOS setup, which stores boot order and records no console session activity at all","Session and logon/logoff events (4624/4634/4647) combined with the user's profile activity artifacts","The DNS cache, which resolves hostnames to IPs and stores no console session information as commonly encountered in real casework","The pagefile header, which describes swap layout and holds no console session records"], correct:1, explanation:"Logon/logoff events and profile artifacts show who was active. The BIOS setup records no sessions, so that option is wrong." },
  { id:70695, domain:4, level:2, question:"Why is the Windows 'ConsentStore' or capability access data (CapabilityAccessManager) useful?", options:["Because it stores the plaintext passwords for apps granted access to the microphone or camera","Because it holds a full memory dump of each app that requested a hardware capability at runtime","It records which apps accessed sensitive resources like the camera, mic, or location, and when","Because it contains the complete network packet capture of every app that used the camera"], correct:2, explanation:"CapabilityAccessManager records app access to camera/mic/location with times. It does not store passwords, so that option is wrong." },
  { id:70696, domain:4, level:3, question:"An examiner needs to reconstruct deleted SQLite records from a browser database. What technique is MOST effective?", options:["Assuming deleted rows are permanently unrecoverable the instant the delete statement executes","Reading only the live table contents, which by definition exclude any deleted records present","Trusting only the WAL file name, which indicates journaling but is not parsed for deleted rows as commonly encountered in real casework","Parsing freelist pages and the write-ahead log (WAL) with SQLite recovery tools to carve deleted rows"], correct:3, explanation:"Parsing freelist pages and the WAL recovers deleted rows. Reading only live tables excludes them, so that option is wrong." },
  { id:70697, domain:4, level:1, question:"What does the acronym LNK refer to in Windows forensics?", options:["A shortcut file that points to a target file or program and preserves useful metadata","A log file format used exclusively by the Windows kernel to record boot-time events as commonly encountered in real casework","A registry hive that stores network share mappings for the currently logged-on user","A compressed archive format Windows uses to store deleted files in the Recycle Bin"], correct:0, explanation:"LNK is a shortcut file preserving target metadata. It is not a kernel boot log format, so that option is wrong." },
  { id:70698, domain:4, level:2, question:"Which artifact best helps confirm that a scheduled task actually executed at a given time?", options:["The BIOS setup, which stores boot order and records no scheduled task execution at all","TaskScheduler/Operational events (100/102/200/201) recording task start and completion with timestamps","The DNS cache, which resolves hostnames to IPs and holds no scheduled task execution data","The pagefile header, which describes swap layout and stores no scheduled task execution records as commonly encountered in real casework"], correct:1, explanation:"TaskScheduler/Operational events record task start/completion. The BIOS setup logs no task execution, so that option is wrong." },
  { id:70699, domain:4, level:2, question:"Why do investigators analyze the Linux systemd journal's boot IDs and persistent storage settings?", options:["Because the journal stores the plaintext passwords for every account defined on the host","Because the journal holds a full memory dump of the kernel taken at each boot of the host","Boot IDs separate events per boot, and persistent storage determines whether logs survive reboots for analysis","Because the journal contains the complete browsing history of every browser on the Linux host as commonly encountered in real casework"], correct:2, explanation:"Boot IDs segment events per boot and persistence controls log survival. The journal does not store account passwords, so that option is wrong." },
  { id:70700, domain:4, level:3, question:"An examiner must build a defensible timeline proving an insider copied files to USB then deleted local copies. What is strongest?", options:["Relying only on the suspect's admission, which lacks corroborating technical evidence entirely","Using only the current file listing, which omits deleted local copies and shows no USB transfer","Trusting only the desktop wallpaper date, which is cosmetic and proves neither copy nor deletion as commonly encountered in real casework","Correlating USBSTOR connection times, LNK volume serials, ShellBags, $Recycle.Bin $I records, and USN journal deletes"], correct:3, explanation:"USBSTOR times, LNK serials, ShellBags, $I records, and USN deletes build a defensible timeline. The suspect's admission alone lacks corroboration, so that is wrong." },
];
if (typeof window !== 'undefined') window.QUESTIONS_CHFI_C3 = QUESTIONS_CHFI_C3;
